module std.algorithm.search

import std.container.array

/**
 * @file std/algorithm/search
 *
 * Search functions for arrays.
 *
 * Provides linear search, binary search, min/max finding,
 * occurrence counting, and index-of-predicate for arrays.
 *
 * @since 0.0.1
 */

friend zone std {
    /**
     *
     */
    @SinceAzora("0.0.1")
    fail SearchError {
        NotFound
        EmptyArray
    }

    /**
     * Performs a linear search for a target in an array.
     *
     * @param arr The array to search.
     * @param target The element to find.
     * @return The index of the first occurrence, or -1 if not found.
     */
    @Experimental(sinceAzora: "0.0.1")
    func linearSearch<T>(arr: Array<T>, target: T): Int {
        for i in 0..<arr.length {
            if arr[i] == target { return i }
        }
        return -1
    }

    /**
     * Performs a binary search on a sorted array.
     *
     * The array must be sorted in ascending order for correct results.
     *
     * @param arr The sorted array to search.
     * @param target The element to find.
     * @return The index of the target, or -1 if not found.
     */
    @Experimental(sinceAzora: "0.0.1")
    func binarySearch<T>(arr: Array<T>, target: T): Int {
        var lo = 0
        var hi = arr.length - 1
        while lo <= hi {
            fin mid = (lo + hi) / 2
            if arr[mid] == target { return mid }
            if arr[mid] < target {
                lo = mid + 1
            } else {
                hi = mid - 1
            }
        }
        return -1
    }

    /**
     * Returns the minimum element in an array.
     *
     * @param arr The array to search (must be non-empty).
     * @return The smallest element.
     */
    @Experimental(sinceAzora: "0.0.1")
    func minOf<T>(arr: Array<T>): T
    in {
        assert arr.length > 0 { "Input must not be empty" }
    } zone {
        var result = arr[0]
        for i in 1..<arr.length {
            if arr[i] < result { result = arr[i] }
        }
        return result
    }

    /**
     * Returns the maximum element in an array.
     *
     * @param arr The array to search (must be non-empty).
     * @return The largest element.
     */
    @Experimental(sinceAzora: "0.0.1")
    func maxOf<T>(arr: Array<T>): T
    in {
        assert arr.length > 0 { "Input must not be empty" }
    } zone {
        var result = arr[0]
        for i in 1..<arr.length {
            if arr[i] > result { result = arr[i] }
        }
        return result
    }

    /**
     * Counts the occurrences of a target in an array.
     *
     * @param arr The array to search.
     * @param target The element to count.
     * @return The number of times target appears in the array.
     */
    @Experimental(sinceAzora: "0.0.1")
    func count<T>(arr: Array<T>, target: T): Int
    out {
        assert it >= 0 { "count must return non-negative" }
    } zone {
        var c = 0
        for i in 0..<arr.length {
            if arr[i] == target { c += 1 }
        }
        return c
    }

    /**
     * Returns the index of the first element satisfying a predicate.
     *
     * @param arr The array to search.
     * @param pred The predicate function.
     * @return The index of the first match, or -1 if none found.
     */
    @Experimental(sinceAzora: "0.0.1")
    func findIndex<T>(arr: Array<T>, pred: (T) -> Bool): Int {
        for i in 0..<arr.length {
            if pred(arr[i]) { return i }
        }
        return -1
    }

    /**
     * Returns the index of the last element satisfying a predicate.
     *
     * @param arr The array to search.
     * @param pred The predicate function.
     * @return The index of the last match, or -1 if none found.
     */
    @Experimental(sinceAzora: "0.0.1")
    func findLastIndex<T>(arr: Array<T>, pred: (T) -> Bool): Int {
        var result = -1
        for i in 0..<arr.length {
            if pred(arr[i]) { result = i }
        }
        return result
    }

    /**
     * Checks if an array contains the given element.
     *
     * @param arr The array to search.
     * @param target The element to look for.
     * @return true if the element is found.
     */
    @Experimental(sinceAzora: "0.0.1")
    func arrayContains<T>(arr: Array<T>, target: T): Bool {
        return linearSearch<T>(arr, target) >= 0
    }
}

