module std.allocator

import std.convert

/**
 * @file std/allocator/allocator
 *
 * memory allocation primitives and custom allocator types.
 *
 * Provides a core.az allocator specification and concrete implementations
 * inspired by Zig's std.mem.allocator design:
 *
 * - Arena: bump allocator for fast, bulk-freed temporary allocations
 * - Pool: fixed-size object pool for uniform allocations
 * - StackAllocator: LIFO allocator for short-lived scratch data
 *
 * All allocators implement the allocator spec and work with the
 * `alloc T(args) in allocator` syntax.
 *
 * @since 0.0.2
 */

friend zone std {

    // -----------------------------------------------------------------------
    // Error Set
    // -----------------------------------------------------------------------

    /**
     * Errors that can occur during memory allocation or deallocation.
     */
    @SinceAzora("0.0.2")
    fail AllocError {
        OutOfMemory,
        InvalidSize,
        DoubleFree,
        UseAfterFree,
        PoolExhausted,
        InvalidAlignment
    }

    // -----------------------------------------------------------------------
    // allocator Specification
    // -----------------------------------------------------------------------

    /**
     * The core.az allocator specification.
     *
     * Any type implementing allocator can be used with the `in` keyword
     * to direct allocations to a specific backing store:
     *
     *     var arena = Arena(1024)
     *     var p = alloc Point(1.0, 2.0) in arena
     */
    @SinceAzora("0.0.2")
    spec Allocator

    // -----------------------------------------------------------------------
    // Arena allocator
    // -----------------------------------------------------------------------

    /**
     * A bump/arena allocator that allocates linearly from a fixed-size region.
     *
     * Allocations are extremely fast (pointer bump). Individual frees are
     * not supported; instead, all memory is released at once via `reset()`
     * or when the arena is destroyed.
     *
     * This is the primary tool for avoiding leaks with short-lived data.
     * Everything allocated in an arena shares a common lifetime.
     *
     * Ideal for:
     * - Frame-scoped temporary data in game loops
     * - Scratch buffers for parsing or rendering
     * - Any pattern where allocations share a common lifetime
     *
     * Usage:
     *
     *     var arena = Arena(64 * 1024)
     *     var particles = alloc Real[1000] in arena
     *     var transforms = alloc Real[1000] in arena
     *     // ... compute ...
     *     arena.reset()   // all allocations freed at once
     *
     * Or with region blocks:
     *
     *     region(32 * 1024) { alloc ->
     *         var verts = alloc Real[600] in alloc
     *     }
     *     // everything freed here
     */
    @SinceAzora("0.0.2")
    pack Arena {
        shield var capacity: Int = 0,
        shield var offset: Int = 0,
        shield var allocCount: Int = 0,
        shield var peakUsage: Int = 0,
        shield var totalAllocated: Int = 0
    }

    impl Allocator for Arena

    /**
     * Creates an arena with the given byte capacity.
     *
     * @param capacity The size of the arena in bytes. Must be positive.
     */
    @Experimental(sinceAzora: "0.0.2")
    impl ctor(capacity: Int) for Arena
    in {
        assert capacity > 0 { "Arena capacity must be positive" }
    } zone { mut self ->
        self.capacity = capacity
        self.offset = 0
        self.allocCount = 0
        self.peakUsage = 0
        self.totalAllocated = 0
    }

    impl Arena {
        /**
         * The number of bytes remaining in the arena.
         */
        @SinceAzora("0.0.2")
        prop remaining: Int = capacity - offset

        /**
         * The number of bytes currently in use.
         */
        @SinceAzora("0.0.2")
        prop used: Int = offset

        /**
         * Whether the arena has no allocations.
         */
        @SinceAzora("0.0.2")
        prop isEmpty: Bool = offset == 0

        /**
         * Requests `size` bytes from the arena.
         *
         * Returns the byte offset of the allocation within the arena,
         * or fails with OutOfMemory if insufficient space remains.
         *
         * @param size The number of bytes to allocate. Must be positive.
         * @return The byte offset of the allocated region.
         */
        @Experimental(sinceAzora: "0.0.2")
        func alloc(size: Int): Int!AllocError
        in {
            assert size > 0 { "Allocation size must be positive" }
        } zone {
            if offset + size > capacity {
                fail return .OutOfMemory
            }
            fin position = offset
            self.offset = offset + size
            self.allocCount = allocCount + 1
            self.totalAllocated = totalAllocated + size
            if offset > peakUsage {
                self.peakUsage = offset
            }
            return position
        }

        /**
         * Requests `size` bytes aligned to `alignment`.
         *
         * Pads the current offset to the next multiple of `alignment`
         * before allocating.
         *
         * @param size The number of bytes to allocate.
         * @param alignment The alignment boundary (must be a power of two).
         * @return The byte offset of the aligned allocation.
         */
        @Experimental(sinceAzora: "0.0.2")
        func allocAligned(size: Int, alignment: Int): Int!AllocError
        in {
            assert size > 0 { "Allocation size must be positive" }
            assert alignment > 0 { "Alignment must be positive" }
        } zone {
            fin remainder = offset % alignment
            fin padding = if remainder == 0 { 0 } else { alignment - remainder }
            fin aligned = offset + padding
            if aligned + size > capacity {
                fail return .OutOfMemory
            }
            self.offset = aligned + size
            self.allocCount = allocCount + 1
            self.totalAllocated = totalAllocated + size + padding
            if offset > peakUsage {
                self.peakUsage = offset
            }
            return aligned
        }

        /**
         * Returns true if the arena can satisfy an allocation of `size` bytes.
         *
         * @param size The number of bytes to check.
         * @return true if sufficient space remains.
         */
        @SinceAzora("0.0.2")
        func canAlloc(size: Int): Bool = offset + size <= capacity

        /**
         * Resets the arena, freeing all allocations at once.
         *
         * After reset, the arena's full capacity is available again.
         * All pointers obtained from previous allocations become invalid.
         */
        @SinceAzora("0.0.2")
        func reset() {
            self.offset = 0
            self.allocCount = 0
        }

        /**
         * Resets the arena and zeroes the peak usage counter.
         */
        @SinceAzora("0.0.2")
        func resetAll() {
            self.offset = 0
            self.allocCount = 0
            self.peakUsage = 0
            self.totalAllocated = 0
        }

        /**
         * Returns a diagnostic summary of arena state.
         *
         * @return A human-readable string with capacity, usage, and allocation count.
         */
        @SinceAzora("0.0.2")
        func diagnostic(): String {
            return "Arena(capacity: " + std::convert::toString(capacity) +
                   ", used: " + std::convert::toString(offset) +
                   ", peak: " + std::convert::toString(peakUsage) +
                   ", allocs: " + std::convert::toString(allocCount) + ")"
        }
    }

    // -----------------------------------------------------------------------
    // Pool allocator
    // -----------------------------------------------------------------------

    /**
     * A fixed-size object pool allocator.
     *
     * Pre-allocates a fixed number of equally-sized slots. Allocation and
     * deallocation are O(1). When a slot is freed, it is returned to the
     * pool for reuse.
     *
     * Ideal for:
     * - Entity/component systems with bounded object counts
     * - Network connection pools
     * - Particle systems with a fixed maximum
     * - Any pattern requiring many same-sized allocations
     *
     * Usage:
     *
     *     var pool = Pool(slotSize: 32, slotCount: 1000)
     *     fin slot1 = try pool.acquire()
     *     fin slot2 = try pool.acquire()
     *     pool.release(slot1)     // slot1 returned to pool
     *     fin slot3 = try pool.acquire()  // reuses slot1's memory
     */
    @SinceAzora("0.0.2")
    pack Pool {
        shield var slotSize: Int = 0
        shield var slotCount: Int = 0
        shield var freeCount: Int = 0
        shield var freeStack: Int* = alloc Int[0]
        shield var acquiredCount: Int = 0
        shield var peakAcquired: Int = 0
    }

    @SinceAzora("0.0.2")
    impl Allocator for Pool

    /**
     * Creates a pool with the given slot size and count.
     *
     * @param slotSize The size of each slot in bytes. Must be positive.
     * @param slotCount The number of slots to pre-allocate. Must be positive.
     */
    @Experimental(sinceAzora: "0.0.2")
    impl ctor(slotSize: Int, slotCount: Int) for Pool
    in {
        assert slotSize > 0 { "Slot size must be positive" }
        assert slotCount > 0 { "Slot count must be positive" }
    } zone { mut self ->
        self.slotSize = slotSize
        self.slotCount = slotCount
        self.freeStack = alloc Int[slotCount]
        self.freeCount = slotCount
        self.acquiredCount = 0
        self.peakAcquired = 0
        for i in 0..<slotCount {
            (*self.freeStack)[i] = slotCount - 1 - i
        }
    }

    @Experimental(sinceAzora: "0.0.2")
    impl dtor() for Pool {
        ref self -> drop self.freeStack
    }

    impl Pool {
        /**
         * Whether the pool is completely exhausted.
         */
        @SinceAzora("0.0.2")
        prop isFull: Bool = freeCount == 0

        /**
         * Whether the pool has no acquired slots.
         */
        @SinceAzora("0.0.2")
        prop isEmpty: Bool = acquiredCount == 0

        /**
         * Whether a slot can be acquired without failing.
         */
        @SinceAzora("0.0.2")
        prop canAcquire: Bool = freeCount > 0

        /**
         * Acquires a slot from the pool.
         *
         * Returns the slot index, or fails with PoolExhausted if all
         * slots are in use.
         *
         * @return The index of the acquired slot.
         */
        @Experimental(sinceAzora: "0.0.2")
        func acquire(): Int!AllocError {
            if freeCount == 0 {
                fail return .PoolExhausted
            }
            self.freeCount = freeCount - 1
            fin slotIndex = (*freeStack)[freeCount]
            self.acquiredCount = acquiredCount + 1
            if acquiredCount > peakAcquired {
                self.peakAcquired = acquiredCount
            }
            return slotIndex
        }

        /**
         * Returns a slot to the pool for reuse.
         *
         * @param slot The index of the slot to release. Must have been
         *             previously acquired.
         */
        @Experimental(sinceAzora: "0.0.2")
        func release(slotIndex: Int)
        in {
            assert slotIndex >= 0 && slotIndex < slotCount { "Invalid slot index" }
        } zone {
            (*freeStack)[freeCount] = slotIndex
            self.freeCount = freeCount + 1
            self.acquiredCount = acquiredCount - 1
        }

        /**
         * Resets the pool, marking all slots as free.
         *
         * All previously acquired slots become invalid.
         */
        @Experimental(sinceAzora: "0.0.2")
        func reset() {
            for i in 0..<slotCount {
                (*freeStack)[i] = slotCount - 1 - i
            }
            self.freeCount = slotCount
            self.acquiredCount = 0
        }

        /**
         * Returns a diagnostic summary of pool state.
         *
         * @return A human-readable string with slot info and usage stats.
         */
        @SinceAzora("0.0.2")
        func diagnostic(): String {
            return "Pool(slots: " + std::convert::toString(slotCount) +
                   ", slotSize: " + std::convert::toString(slotSize) +
                   ", inUse: " + std::convert::toString(acquiredCount) +
                   ", free: " + std::convert::toString(freeCount) +
                   ", peak: " + std::convert::toString(peakAcquired) + ")"
        }
    }

    // -----------------------------------------------------------------------
    // Stack allocator
    // -----------------------------------------------------------------------

    /**
     * A LIFO (last-in, first-out) stack allocator.
     *
     * Allocations and deallocations follow strict LIFO order. Freeing
     * must happen in the reverse order of allocation. This is ideal for
     * function-scoped scratch data where allocation lifetimes are nested.
     *
     * Compared to Arena:
     * - Arena: no individual free, bulk reset only
     * - StackAllocator: individual free in LIFO order, plus bulk reset
     *
     * Usage:
     *
     *     var stack = StackAllocator(4096)
     *     fin a = try stack.alloc(64)
     *     fin b = try stack.alloc(128)
     *     stack.free(128)  // frees b
     *     stack.free(64)   // frees a
     */
    @SinceAzora("0.0.2")
    pack StackAllocator {
        shield var capacity: Int = 0
        shield var offset: Int = 0
        shield var allocCount: Int = 0
        shield var peakUsage: Int = 0
    }

    @SinceAzora("0.0.2")
    impl Allocator for StackAllocator

    /**
     * Creates a stack allocator with the given byte capacity.
     *
     * @param capacity The total size in bytes. Must be positive.
     */
    @Experimental(sinceAzora: "0.0.2")
    impl ctor(capacity: Int) for StackAllocator
    in {
        assert capacity > 0 { "StackAllocator capacity must be positive" }
    } zone { mut self ->
        self.capacity = capacity
        self.offset = 0
        self.allocCount = 0
        self.peakUsage = 0
    }

    impl StackAllocator {
        /**
         * The number of bytes remaining.
         */
        @SinceAzora("0.0.2")
        prop remaining: Int = capacity - offset

        /**
         * Whether the stack has no allocations.
         */
        @SinceAzora("0.0.2")
        prop isEmpty: Bool = offset == 0

        /**
         * Allocates `size` bytes from the top of the stack.
         *
         * @param size The number of bytes to allocate. Must be positive.
         * @return The byte offset of the allocation.
         */
        @Experimental(sinceAzora: "0.0.2")
        func alloc(size: Int): Int!AllocError
        in {
            assert size > 0 { "Allocation size must be positive" }
        } zone {
            if offset + size > capacity {
                fail return .OutOfMemory
            }
            fin position = offset
            self.offset = offset + size
            self.allocCount = allocCount + 1
            if offset > peakUsage {
                self.peakUsage = offset
            }
            return position
        }

        /**
         * Frees `size` bytes from the top of the stack (LIFO order).
         *
         * The caller must free in the reverse order of allocation.
         *
         * @param size The number of bytes to free. Must match the most
         *             recent allocation.
         */
        @Experimental(sinceAzora: "0.0.2")
        func free(size: Int)
        in {
            assert size > 0 { "Free size must be positive" }
            assert size <= offset { "Cannot free more than allocated" }
        } zone {
            self.offset = offset - size
            self.allocCount = allocCount - 1
        }

        /**
         * Returns true if the stack can satisfy an allocation of `size` bytes.
         *
         * @param size The number of bytes to check.
         * @return true if sufficient space remains.
         */
        @SinceAzora("0.0.2")
        func canAlloc(size: Int): Bool = offset + size <= capacity

        /**
         * Resets the stack, freeing all allocations.
         */
        @SinceAzora("0.0.2")
        func reset() {
            self.offset = 0
            self.allocCount = 0
        }

        /**
         * Resets the stack and clears peak tracking.
         */
        @SinceAzora("0.0.2")
        func resetAll() {
            self.offset = 0
            self.allocCount = 0
            self.peakUsage = 0
        }

        /**
         * Returns a diagnostic summary.
         *
         * @return A human-readable string with capacity, usage, and stats.
         */
        @SinceAzora("0.0.2")
        func diagnostic(): String {
            return "StackAllocator(capacity: " + std::convert::toString(capacity) +
                   ", used: " + std::convert::toString(offset) +
                   ", peak: " + std::convert::toString(peakUsage) +
                   ", allocs: " + std::convert::toString(allocCount) + ")"
        }
    }

    // -----------------------------------------------------------------------
    // Alloc Scope (Factory Functions)
    // -----------------------------------------------------------------------

    /**
     * Convenience factory for creating allocators.
     *
     * Usage:
     *
     *     var arena = Alloc.arena(64 * 1024)
     *     var pool = Alloc.pool(slotSize: 32, count: 100)
     *     var stack = Alloc.stack(4096)
     */
    zone Alloc {
        /**
         * Creates an arena allocator with the given byte capacity.
         *
         * @param size The size of the arena in bytes.
         * @return A new Arena allocator.
         */
        @Experimental(sinceAzora: "0.0.2")
        func arena(size: Int): Arena
        in {
            assert size > 0 { "Arena size must be positive" }
        } zone {
            return Arena(size)
        }

        /**
         * Creates a pool allocator with the given slot configuration.
         *
         * @param slotSize The size of each slot in bytes.
         * @param count The number of pre-allocated slots.
         * @return A new Pool allocator.
         */
        @Experimental(sinceAzora: "0.0.2")
        func pool(slotSize: Int, count: Int): Pool
        in {
            assert slotSize > 0 { "Slot size must be positive" }
            assert count > 0 { "Slot count must be positive" }
        } zone {
            return Pool(slotSize, count)
        }

        /**
         * Creates a stack allocator with the given byte capacity.
         *
         * @param size The size of the stack in bytes.
         * @return A new StackAllocator.
         */
        @Experimental(sinceAzora: "0.0.2")
        func stack(size: Int): StackAllocator
        in {
            assert size > 0 { "Stack size must be positive" }
        } zone {
            return StackAllocator(size)
        }
    }
}

