module std.char

/**
 * @file std/char
 *
 * Character utilities and Unicode support.
 *
 * Provides functions for character classification, conversion,
 * and Unicode code point manipulation. Characters in Azora are
 * Unicode code points represented by the Char type.
 *
 * @since 0.0.1
 */

export import std.char.core

friend zone std {
    /**
     * Returns the Unicode code point of a character.
     *
     * @param c The character to convert.
     * @return The integer code point.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charToCode(c: Char): Int {
        return ord(c)
    }

    /**
     * Returns the character for a Unicode code point.
     *
     * @param code The code point (must be a valid Unicode value).
     * @return The character at the given code point.
     */
    @Experimental(sinceAzora: "0.0.1")
    func codeToChar(code: Int): Char
    in {
        assert code >= 0 { "Code point must be non-negative" }
    } zone {
        return chr(code)
    }

    /**
     * Checks if a character is an ASCII digit (0-9).
     *
     * @param c The character to check.
     * @return true if c is a digit.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsDigit(c: Char): Bool {
        return isDigit(c)
    }

    /**
     * Checks if a character is an ASCII letter (a-z, A-Z).
     *
     * @param c The character to check.
     * @return true if c is a letter.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsAlpha(c: Char): Bool {
        return isAlpha(c)
    }

    /**
     * Checks if a character is alphanumeric.
     *
     * @param c The character to check.
     * @return true if c is a letter or digit.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsAlphanumeric(c: Char): Bool {
        return isAlphanumeric(c)
    }

    /**
     * Checks if a character is uppercase.
     *
     * @param c The character to check.
     * @return true if c is an uppercase letter.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsUpper(c: Char): Bool {
        return isUpper(c)
    }

    /**
     * Checks if a character is lowercase.
     *
     * @param c The character to check.
     * @return true if c is a lowercase letter.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsLower(c: Char): Bool {
        return isLower(c)
    }

    /**
     * Checks if a character is whitespace.
     *
     * @param c The character to check.
     * @return true if c is a whitespace character.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsWhitespace(c: Char): Bool {
        return isWhitespace(c)
    }

    /**
     * Converts a character to uppercase.
     *
     * @param c The character to convert.
     * @return The uppercase version of c.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charToUpper(c: Char): Char {
        return toUpper(c)
    }

    /**
     * Converts a character to lowercase.
     *
     * @param c The character to convert.
     * @return The lowercase version of c.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charToLower(c: Char): Char {
        return toLower(c)
    }

    /**
     * Checks if a character is an ASCII character (code 0-127).
     *
     * @param c The character to check.
     * @return true if c is in the ASCII range.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsAscii(c: Char): Bool {
        fin code = ord(c)
        return code >= 0 && code <= 127
    }

    /**
     * Checks if a character is a printable ASCII character (code 32-126).
     *
     * @param c The character to check.
     * @return true if c is printable.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsPrintable(c: Char): Bool {
        fin code = ord(c)
        return code >= 32 && code <= 126
    }

    /**
     * Checks if a character is a hexadecimal digit (0-9, a-f, A-F).
     *
     * @param c The character to check.
     * @return true if c is a hex digit.
     */
    @Experimental(sinceAzora: "0.0.1")
    func charIsHexDigit(c: Char): Bool {
        fin code = ord(c)
        return (code >= 48 && code <= 57) ||
               (code >= 65 && code <= 70) ||
               (code >= 97 && code <= 102)
    }

    /**
     * Converts a hex digit character to its integer value.
     *
     * @param c The hex digit character.
     * @return The integer value (0-15).
     */
    @Experimental(sinceAzora: "0.0.1")
    func hexDigitToInt(c: Char): Int
    in {
        assert (charIsHexDigit(c)) { "Character must be a hex digit" }
    } zone {
        fin code = ord(c)
        if code >= 48 && code <= 57 { return code - 48 }
        if code >= 65 && code <= 70 { return code - 55 }
        return code - 87
    }

    /**
     * Converts a digit character to its integer value.
     *
     * @param c The digit character.
     * @return The integer value (0-9).
     */
    @Experimental(sinceAzora: "0.0.1")
    func digitToInt(c: Char): Int
    in {
        assert (isDigit(c)) { "Character must be a digit" }
    } zone {
        return ord(c) - 48
    }

    /**
     * Converts an integer (0-9) to a digit character.
     *
     * @param n The integer to convert.
     * @return The digit character.
     */
    @Experimental(sinceAzora: "0.0.1")
    func intToDigit(n: Int): Char
    in {
        assert n >= 0 && n <= 9 { "Integer must be 0-9" }
    } zone {
        return chr(n + 48)
    }
}

