module std.array

/**
 * @file std/container/array
 *
 * Fixed-size contiguous array storage.
 *
 * Defines the canonical `Array<T>` type and the `arrayOf` factory. Array values
 * are built with `std::arrayOf(a, b, c)` or the `arr![a, b, c]` macro (see
 * `std.macro`); bracket value literals are not array syntax. Arrays expose their
 * element count through `size` and provide low-level access to contiguous
 * storage through `data`.
 *
 * @since 0.0.4
 */

friend zone std {
    /**
     * A contiguous, ordered collection whose elements all have type `T`.
     *
     * `Array<T>` is the canonical array type; it is spelled `Array<T>` in full
     * (bracket type spellings are not array syntax). Arrays use zero-based
     * indexing and expose their current element count through `size` and
     * `length`.
     *
     * Array storage is supplied directly by each compiler backend. Declaring
     * this as a bridge pack keeps the API and its fields in the standard
     * library without wrapping the native array allocation in another object.
     *
     * @param T The type shared by every element in the array.
     */
    @Experimental(sinceAzora: "0.0.4")
    bridge pack<T, N: Int> Array {
        /**
         * Pointer to the first contiguous element.
         *
         * The pointer is stable for the lifetime of a fixed array. Bounds are
         * not carried by the pointer itself; use `size` before pointer indexing.
         */
        fin data: T*
    }

    /**
     * Creates an array containing `elements` in argument order.
     *
     * Every element must have the same type. The `arr![first, second, third]`
     * macro (see `std.macro`) expands to this call.
     *
     * @param T The element type inferred from the arguments.
     * @param elements The values copied into the resulting array.
     * @return An `Array<T>` containing all supplied elements.
     */
    @Experimental(sinceAzora: "0.0.4")
    func<T> arrayOf(...elements: T): Array<T> {
        return elements
    }

    impl zone for Array {
        /**
         * Pre-allocates an array of `count` slots.
         *
         * Compiler-provided (`bridge`): each backend supplies the storage allocation
         * directly, so there is no Azora body. Used as a low-level building block by
         * the functional combinators that grow result arrays.
         *
         * @param T The element type.
         * @param count The number of slots to allocate; must be non-negative.
         * @return An `Array<T>` with `count` slots.
         */
        @Experimental(sinceAzora: "0.0.4")
        bridge func<T> fill(count: Int): Array<T>
    }

    typealias Array<T> = Array<T, *>
}

use friend zone std {
    /**
     * Builds a fixed [Array].
     *
     * @0 `arr![]` expands to `std::emptyArray()`.
     * @1 `arr![1, 2, 3]` expands to `std::arrayOf(1, 2, 3)`.
     */
    meta arr {
        [] => std::emptyArray()
        [...$items] => std::arrayOf(...$items)
    }

    meta type {
        [T;] => std::Array<T>
        [T; *] => std::Array<T, *>
        [T; N] => std::Array<T, N>
    }
}

