module std.container.map

import std.container.array

import std.container.list

/**
 * @file std/container/map
 *
 * Proposed native map hierarchy for Azora.
 *
 * Maps use operators supplied by their key and value types. There are no
 * runtime hasher, equality, or comparator objects:
 *
 * - `HashMap<K, V>` and `LinkedHashMap<K, V>` require `oper#` and `oper==`
 *   for `K`.
 * - `TreeMap<K, V>` requires `oper<` for `K`.
 * - `containsValue`, structural `oper==`, and structural `oper#` instantiate
 *   only when the corresponding value operators exist.
 *
 * `oper[start:stop:step]` returns a snapshot of the map's entries using its
 * iteration order. `start` is inclusive, `stop` is exclusive, and `step`
 * defaults to `1`. Omitting `start` begins from the first entry, omitting
 * `stop` continues to the last entry, and negative indices count backward from
 * the end. The result is always a `LinkedHashMap` snapshot, preserving the
 * observed iteration order even when the source is a `HashMap`. Key ranges on
 * sorted maps use `subMap`, `headMap`, and `tailMap`; this avoids ambiguity
 * when `K` is an integer type.
 *
 * @since 0.0.4
 */

friend zone std {
    /**
     * One immutable key-value association.
     *
     * @param K The key type.
     * @param V The value type.
     */
    @Experimental(sinceAzora: "0.0.4")
    pack<K, V> MapEntry {
        fin key: K
        fin value: V
    }

    /**
     * Read-only behavior shared by every map implementation.
     *
     * `Map` does not promise a particular iteration order. A concrete pack may
     * provide a stronger guarantee. Index access returns `null` for an absent
     * key, matching Kotlin map access.
     *
     * @param K The key type.
     * @param V The value type.
     */
    @Experimental(sinceAzora: "0.0.4")
    spec Map<K, V> {
        /** Number of unique keys. */
        prop size: Int

        /** Whether this map has no entries. */
        prop isEmpty: Bool

        /** Whether this map has at least one entry. */
        prop isNotEmpty: Bool

        /** Returns whether `key` is present. */
        func containsKey(key: ref K): Bool

        /** Returns whether an equal value is present. Requires `oper==` for `V`. */
        func containsValue(value: ref V): Bool

        /** Returns the value associated with `key`, or `null` when absent. */
        func get(key: ref K): V?

        /** Returns the associated value, or `defaultValue` when absent. */
        func getOrDefault(key: ref K, defaultValue: V): V

        /** Returns an iteration-order snapshot of all entries. */
        func entries(): Array<MapEntry<K, V>>

        /** Returns an iteration-order snapshot of all keys. */
        func keys(): List<K>

        /** Returns an iteration-order snapshot of all values. */
        func values(): List<V>

        /** Invokes `action` once for every entry in iteration order. */
        func forEach(action: (ref K, ref V) -> Unit)
    }

    /**
     * Mutation behavior implemented by mutable map packs.
     *
     * Mutation always receives `mut ref self`. Implementing this spec does not
     * weaken a `ref Map<K, V>` view: callers holding only a shared reference can
     * still use only read operations.
     *
     * @param K The key type.
     * @param V The value type.
     */
    @Experimental(sinceAzora: "0.0.4")
    spec MutableMap<K, V> : Map<K, V> {
        /** Associates `key` with `value` and returns the replaced value, if any. */
        func put(key: K, value: V): V?

        /** Copies all entries from `other`, replacing equal keys. */
        func putAll(other: ref Map<K, V>)

        /** Removes `key` and returns its previous value, or `null` when absent. */
        func remove(key: ref K): V?

        /** Removes every entry while retaining reusable internal capacity. */
        func clear()

        /** Returns the existing value or inserts and returns `defaultValue()`. */
        func getOrPut(key: K, defaultValue: () -> V): V
    }

    /**
     * Ordered navigation supplied by maps whose keys obey `oper<`.
