    spec SortedMap<K, V> {
        /** Returns the smallest key, or `null` when empty. */
        func firstKey(): K?

        /** Returns the greatest key, or `null` when empty. */
        func lastKey(): K?

        /** Returns the greatest key strictly below `key`. */
        func lowerKey(key: ref K): K?

        /** Returns the greatest key below or equivalent to `key`. */
        func floorKey(key: ref K): K?

        /** Returns the smallest key equivalent to or above `key`. */
        func ceilingKey(key: ref K): K?

        /** Returns the smallest key strictly above `key`. */
        func higherKey(key: ref K): K?

        /** Returns the entry with the smallest key, or `null` when empty. */
        func firstEntry(): MapEntry<K, V>?

        /** Returns the entry with the greatest key, or `null` when empty. */
        func lastEntry(): MapEntry<K, V>?

        /** Returns an ascending read-only view below `toKey`. */
        func headMap(toKey: ref K, inclusive: Bool = false): SortedMap<K, V>

        /** Returns an ascending read-only view above `fromKey`. */
