     * Polling removes and returns a boundary entry in one tree operation.
     */
    @Experimental(sinceAzora: "0.0.4")
    spec MutableSortedMap<K, V> : SortedMap<K, V> {
        /** Removes and returns the smallest entry, or `null` when empty. */
        func pollFirstEntry(): MapEntry<K, V>?

        /** Removes and returns the greatest entry, or `null` when empty. */
        func pollLastEntry(): MapEntry<K, V>?
