    /** Hash table with unspecified iteration order. `K` requires `oper#` and `oper==`. */
    @Experimental(sinceAzora: "0.0.4")
    pack<K, V> HashMap {
        shield var keys: K* = alloc K[16]
        shield var values: V* = alloc V[16]
        shield var hashes: ULong* = alloc ULong[16]
        shield var occupied: Bool* = alloc Bool[16]
        confine var _size: Int = 0
        shield var capacity: Int = 16
    }

    /** Hash table whose dense entry storage preserves insertion order. */
    @Experimental(sinceAzora: "0.0.4")
    pack<K, V> LinkedHashMap {
        shield var keys: K* = alloc K[16]
        shield var values: V* = alloc V[16]
        shield var hashes: ULong* = alloc ULong[16]
        shield var buckets: Int* = alloc Int[32]
        confine var _size: Int = 0
        shield var capacity: Int = 16
        shield var bucketCapacity: Int = 32
    }

    /** AVL tree map ordered exclusively through `oper<` for `K`. */
    @Experimental(sinceAzora: "0.0.4")
    pack<K, V> TreeMap {
        shield var keys: K* = alloc K[16]
        shield var values: V* = alloc V[16]
        shield var left: Int* = alloc Int[16]
        shield var right: Int* = alloc Int[16]
        shield var parent: Int* = alloc Int[16]
        shield var heights: Int* = alloc Int[16]
        shield var freeNext: Int* = alloc Int[16]
        shield var root: Int = -1
        shield var freeHead: Int = -1
        shield var elemCount: Int = 0
        confine var _size: Int = 0
        shield var capacity: Int = 16
    }

    /** Normalized operands delivered to `oper[:]` for slicing. */
    @Experimental(sinceAzora: "0.0.4")
    pack MapSlice {
        fin start: Int
        fin end: Int
        fin step: Int = 1
    }

    // ---------------------------------------------------------------------
    // HashMap implementation
    // ---------------------------------------------------------------------

    impl ctor() for HashMap<K, V> { mut ref self ->
        for i in 0..<self.capacity {
            self.occupied[i] = false
        }
    }

    impl dtor() for HashMap<K, V> {
        ref self ->
        drop self.keys
        drop self.values
        drop self.hashes
        drop self.occupied
    }

    impl HashMap<K, V> {
        confine func bucketFor(hash: ULong): Int { ref self ->
            return (hash % (self.capacity as ULong)) as Int
        }

        confine func findIndex(key: ref K): Int { ref self ->
            fin hash = #key
            var index = self.bucketFor(hash)
            for visited in 0..<self.capacity {
                if !self.occupied[index] { return -1 }
                if self.hashes[index] == hash && self.keys[index] == key { return index }
                index = (index + 1) % self.capacity
            }
            return -1
        }

        confine func insertKnownHash(key: K, value: V, hash: ULong): V? { mut ref self ->
            var index = self.bucketFor(hash)
            while self.occupied[index] {
                if self.hashes[index] == hash && self.keys[index] == key {
                    fin previous = self.values[index]
                    self.values[index] = value
                    return previous
                }
                index = (index + 1) % self.capacity
            }
            self.keys[index] = key
            self.values[index] = value
            self.hashes[index] = hash
            self.occupied[index] = true
            self._size += 1
            return null
        }

        confine func rehash(newCapacity: Int) { mut ref self ->
            fin oldKeys = self.keys
            fin oldValues = self.values
            fin oldHashes = self.hashes
            fin oldOccupied = self.occupied
            fin oldCapacity = self.capacity

            self.keys = alloc K[newCapacity]
            self.values = alloc V[newCapacity]
            self.hashes = alloc ULong[newCapacity]
            self.occupied = alloc Bool[newCapacity]
            self.capacity = newCapacity
            self._size = 0

            var i = 0
            while i < newCapacity {
                self.occupied[i] = false
                i += 1
            }
            i = 0
            while i < oldCapacity {
                if oldOccupied[i] {
                    self.insertKnownHash(oldKeys[i], oldValues[i], oldHashes[i])
                }
                i += 1
            }
            drop oldKeys
            drop oldValues
            drop oldHashes
            drop oldOccupied
        }

        confine func ensureInsertCapacity() { mut ref self ->
            if (self._size + 1) * 10 >= self.capacity * 7 {
                self.rehash(self.capacity * 2)
            }
        }

        confine func putValue(key: K, value: V): V? { mut ref self ->
            self.ensureInsertCapacity()
            fin hash = #key
            return self.insertKnownHash(key, value, hash)
        }

        confine func removeValue(key: ref K): V? { mut ref self ->
            fin found = self.findIndex(key)
            if found < 0 { return null }
            fin previous = self.values[found]
            self.occupied[found] = false
            self._size -= 1

            var index = (found + 1) % self.capacity
            while self.occupied[index] {
                fin movedKey = self.keys[index]
                fin movedValue = self.values[index]
                fin movedHash = self.hashes[index]
                self.occupied[index] = false
                self._size -= 1
                self.insertKnownHash(movedKey, movedValue, movedHash)
                index = (index + 1) % self.capacity
            }
            return previous
        }

        confine func entrySnapshot(): Array<MapEntry<K, V>> { ref self ->
            var result: Array<MapEntry<K, V>> = Array::fill<MapEntry<K, V>>(self._size)
            var source = 0
            var target = 0
            while source < self.capacity {
                if self.occupied[source] {
                    result[target] = MapEntry(self.keys[source], self.values[source])
                    target += 1
                }
                source += 1
            }
            return result
        }
    }

    impl Map<K, V> for HashMap<K, V> {
        prop size: Int = self._size
        prop isEmpty: Bool = self._size == 0
        prop isNotEmpty: Bool = self._size > 0

        func containsKey(key: ref K): Bool { ref self -> return self.findIndex(key) >= 0 }

        func containsValue(value: ref V): Bool { ref self ->
            for i in 0..<self.capacity {
                if self.occupied[i] && self.values[i] == value { return true }
            }
            return false
        }

        func get(key: ref K): V? { ref self ->
            fin index = self.findIndex(key)
            if index < 0 { return null }
            return self.values[index]
        }

        func getOrDefault(key: ref K, defaultValue: V): V { ref self ->
            fin index = self.findIndex(key)
            if index < 0 { return defaultValue }
            return self.values[index]
        }

        func entries(): Array<MapEntry<K, V>> { ref self -> return self.entrySnapshot() }

        func keys(): List<K> { ref self ->
            fin all = self.entries()
            var result: Array<K> = Array::fill<K>(all.size)
            for i in 0..<all.size {
                result[i] = all[i].key
            }
            return result
        }

        func values(): List<V> { ref self ->
            fin all = self.entrySnapshot()
            var result: Array<V> = Array::fill<V>(all.size)
            for i in 0..<all.size {
                result[i] = all[i].value
            }
            return result
        }

        func forEach(action: (ref K, ref V) -> Unit) { ref self ->
            for i in 0..<self.capacity {
                if self.occupied[i] {
                    action(self.keys[i], self.values[i])
                }
            }
        }
    }

    impl MutableMap<K, V> for HashMap<K, V> {
        func put(key: K, value: V): V? { mut ref self ->
            return self.putValue(key, value)
        }

        func putAll(other: ref Map<K, V>) { mut ref self ->
            fin all = other.entries()
            for i in 0..<all.size {
                self.putValue(all[i].key, all[i].value)
            }
        }

        func remove(key: ref K): V? { mut ref self ->
            return self.removeValue(key)
        }

        func clear() { mut ref self ->
            for i in 0..<self.capacity {
                self.occupied[i] = false
            }
            self._size = 0
        }

        func getOrPut(key: K, defaultValue: () -> V): V { mut ref self ->
            fin index = self.findIndex(key)
            if index >= 0 { return self.values[index] }
            fin value = defaultValue()
            self.putValue(key, value)
            return value
        }
    }

    // ---------------------------------------------------------------------
    // LinkedHashMap implementation
    // ---------------------------------------------------------------------

    impl ctor() for LinkedHashMap<K, V> { mut ref self ->
        for i in 0..<self.bucketCapacity {
            self.buckets[i] = -1
        }
    }

    impl dtor() for LinkedHashMap<K, V> { ref self ->
        drop self.keys
        drop self.values
        drop self.hashes
        drop self.buckets
    }

    impl LinkedHashMap<K, V> {
        confine func findIndex(key: ref K): Int { ref self ->
            fin hash = #key
            var bucket = (hash % (self.bucketCapacity as ULong)) as Int
            for visited in 0..<self.bucketCapacity {
                fin index = self.buckets[bucket]
                if index < 0 { return -1 }
                if self.hashes[index] == hash && self.keys[index] == key { return index }
                bucket = (bucket + 1) % self.bucketCapacity
            }
            return -1
        }

        confine func insertBucket(index: Int) { mut ref self ->
            var bucket = (self.hashes[index] % (self.bucketCapacity as ULong)) as Int
            while self.buckets[bucket] >= 0 {
                bucket = (bucket + 1) % self.bucketCapacity
            }
            self.buckets[bucket] = index
        }

        confine func rebuildBuckets(newCapacity: Int) { mut ref self ->
            fin oldBuckets = self.buckets
            self.buckets = alloc Int[newCapacity]
            self.bucketCapacity = newCapacity
            var i = 0
            while i < newCapacity {
                self.buckets[i] = -1
                i += 1
            }
            i = 0
            while i < self._size {
                self.insertBucket(i)
                i += 1
            }
            drop oldBuckets
        }

        confine func growEntries() { mut ref self ->
            fin newCapacity = self.capacity * 2
            fin newKeys = alloc K[newCapacity]
            fin newValues = alloc V[newCapacity]
            fin newHashes = alloc ULong[newCapacity]
            for i in 0..<self._size {
                newKeys[i] = self.keys[i]
                newValues[i] = self.values[i]
                newHashes[i] = self.hashes[i]
            }
            fin oldKeys = self.keys
            fin oldValues = self.values
            fin oldHashes = self.hashes
            self.keys = newKeys
            self.values = newValues
            self.hashes = newHashes
            self.capacity = newCapacity
            drop oldKeys
            drop oldValues
            drop oldHashes
        }

        confine func putValue(key: K, value: V): V? { mut ref self ->
            fin found = self.findIndex(key)
            if found >= 0 {
                fin previous = self.values[found]
                self.values[found] = value
                return previous
            }
            if self._size >= self.capacity {
                self.growEntries()
            }
            if (self._size + 1) * 10 >= self.bucketCapacity * 7 {
                self.rebuildBuckets(self.bucketCapacity * 2)
            }
            fin hash = #key
            self.keys[self._size] = key
            self.values[self._size] = value
            self.hashes[self._size] = hash
            self.insertBucket(self._size)
            self._size += 1
            return null
        }

        confine func removeValue(key: ref K): V? { mut ref self ->
            fin found = self.findIndex(key)
            if found < 0 { return null }
            fin previous = self.values[found]
            for i in found..<self._size - 1 {
                self.keys[i] = self.keys[i + 1]
                self.values[i] = self.values[i + 1]
                self.hashes[i] = self.hashes[i + 1]
            }
            self._size -= 1
            self.rebuildBuckets(self.bucketCapacity)
            return previous
        }

        confine func entrySnapshot(): Array<MapEntry<K, V>> { ref self ->
            var result: Array<MapEntry<K, V>> = Array::fill<MapEntry<K, V>>(self._size)
            for i in 0..<self._size {
                result[i] = MapEntry(self.keys[i], self.values[i])
            }
            return result
        }
    }

    impl Map<K, V> for LinkedHashMap<K, V> {
        prop size: Int = self._size
        prop isEmpty: Bool = self._size == 0
        prop isNotEmpty: Bool = self._size > 0

        func containsKey(key: ref K): Bool { ref self ->
