    // ---------------------------------------------------------------------
    // TreeMap implementation (AVL balanced tree)
    // ---------------------------------------------------------------------

    impl dtor() for TreeMap<K, V> { ref self ->
        drop self.keys
        drop self.values
        drop self.left
        drop self.right
        drop self.parent
        drop self.heights
        drop self.freeNext
    }

    impl TreeMap<K, V> {
        confine func elemHeight(elem: Int): Int { ref self ->
            if elem < 0 { return 0 }
            return self.heights[elem]
        }

        confine func updateHeight(elem: Int) { mut ref self ->
            if elem < 0 { return }
            fin leftHeight = self.elemHeight(self.left[elem])
            fin rightHeight = self.elemHeight(self.right[elem])
            self.heights[elem] = if leftHeight > rightHeight {
                leftHeight + 1
            } else {
                rightHeight + 1
            }
        }

        confine func grow() { mut ref self ->
            fin newCapacity = self.capacity * 2
            fin newKeys = alloc K[newCapacity]
            fin newValues = alloc V[newCapacity]
            fin newLeft = alloc Int[newCapacity]
            fin newRight = alloc Int[newCapacity]
            fin newParent = alloc Int[newCapacity]
            fin newHeights = alloc Int[newCapacity]
            fin newFreeNext = alloc Int[newCapacity]
            for i in 0..<self.elemCount {
                newKeys[i] = self.keys[i]
                newValues[i] = self.values[i]
                newLeft[i] = self.left[i]
                newRight[i] = self.right[i]
                newParent[i] = self.parent[i]
                newHeights[i] = self.heights[i]
                newFreeNext[i] = self.freeNext[i]
            }
            drop self.keys
            drop self.values
            drop self.left
            drop self.right
            drop self.parent
            drop self.heights
            drop self.freeNext
            self.keys = newKeys
            self.values = newValues
            self.left = newLeft
            self.right = newRight
            self.parent = newParent
            self.heights = newHeights
            self.freeNext = newFreeNext
            self.capacity = newCapacity
        }

        confine func allocateNode(key: K, value: V, parent: Int): Int { mut ref self ->
            var elem = self.freeHead
            if elem >= 0 {
                self.freeHead = self.freeNext[elem]
            } else {
                if self.elemCount >= self.capacity {
                    self.grow()
                }
                elem = self.elemCount
                self.elemCount += 1
            }
            self.keys[elem] = key
            self.values[elem] = value
            self.left[elem] = -1
            self.right[elem] = -1
            self.parent[elem] = parent
            self.heights[elem] = 1
            self._size += 1
            return elem
        }

        confine func releaseNode(elem: Int) { mut ref self ->
            self.freeNext[elem] = self.freeHead
            self.freeHead = elem
            self._size -= 1
        }

        confine func replaceParentChild(parent: Int, oldChild: Int, newChild: Int) { mut ref self ->
            if parent < 0 {
                self.root = newChild
            } else if self.left[parent] == oldChild {
                self.left[parent] = newChild
            } else {
                self.right[parent] = newChild
            }
            if newChild >= 0 { self.parent[newChild] = parent }
        }

        confine func rotateLeft(elem: Int): Int { mut ref self ->
            fin pivot = self.right[elem]
            fin oldParent = self.parent[elem]
            self.right[elem] = self.left[pivot]
            if self.right[elem] >= 0 {
                self.parent[self.right[elem]] = elem
            }
            self.left[pivot] = elem
            self.parent[elem] = pivot
            self.parent[pivot] = oldParent
            self.replaceParentChild(oldParent, elem, pivot)
            self.updateHeight(elem)
            self.updateHeight(pivot)
            return pivot
        }

        confine func rotateRight(elem: Int): Int { mut ref self ->
            fin pivot = self.left[elem]
            fin oldParent = self.parent[elem]
            self.left[elem] = self.right[pivot]
            if self.left[elem] >= 0 {
                self.parent[self.left[elem]] = elem
            }
            self.right[pivot] = elem
            self.parent[elem] = pivot
            self.parent[pivot] = oldParent
            self.replaceParentChild(oldParent, elem, pivot)
            self.updateHeight(elem)
            self.updateHeight(pivot)
            return pivot
        }

        confine func rebalanceFrom(start: Int) { mut ref self ->
            var elem = start
            while elem >= 0 {
                self.updateHeight(elem)
                fin balance = self.elemHeight(self.left[elem]) - self.elemHeight(self.right[elem])
                if balance > 1 {
                    if self.elemHeight(self.left[self.left[elem]]) < self.elemHeight(self.right[self.left[elem]]) {
                        self.rotateLeft(self.left[elem])
                    }
                    fin top = self.rotateRight(elem)
                    elem = self.parent[top]
                } else if balance < -1 {
                    if self.elemHeight(self.right[self.right[elem]]) < self.elemHeight(self.left[self.right[elem]]) {
                        self.rotateRight(self.right[elem])
                    }
                    fin top = self.rotateLeft(elem)
                    elem = self.parent[top]
                } else {
                    elem = self.parent[elem]
                }
            }
        }

        confine func findNode(key: ref K): Int { ref self ->
            var elem = self.root
            while elem >= 0 {
                if key < self.keys[elem] {
                    elem = self.left[elem]
                } else if self.keys[elem] < key {
                    elem = self.right[elem]
                } else {
                    return elem
                }
            }
            return -1
        }

        confine func putValue(key: K, value: V): V? { mut ref self ->
            if self.root < 0 {
                self.root = self.allocateNode(key, value, -1)
                return null
            }
            var elem = self.root
            var parent = -1
            while elem >= 0 {
                parent = elem
                if key < self.keys[elem] {
                    elem = self.left[elem]
                } else if self.keys[elem] < key {
                    elem = self.right[elem]
                } else {
                    fin previous = self.values[elem]
                    self.values[elem] = value
                    return previous
                }
            }
            fin inserted = self.allocateNode(key, value, parent)
            if key < self.keys[parent] {
                self.left[parent] = inserted
            } else {
                self.right[parent] = inserted
            }
            self.rebalanceFrom(parent)
            return null
        }

        confine func minimumNode(start: Int): Int { ref self ->
            var elem = start
            if elem < 0 { return -1 }
            while self.left[elem] >= 0 {
                elem = self.left[elem]
            }
            return elem
        }

        confine func maximumNode(start: Int): Int { ref self ->
            var elem = start
            if elem < 0 { return -1 }
            while self.right[elem] >= 0 {
                elem = self.right[elem]
            }
            return elem
        }

        confine func removeValue(key: ref K): V? { mut ref self ->
            var elem = self.findNode(key)
            if elem < 0 { return null }
            fin previous = self.values[elem]

            if self.left[elem] >= 0 && self.right[elem] >= 0 {
                fin successor = self.minimumNode(self.right[elem])
                self.keys[elem] = self.keys[successor]
                self.values[elem] = self.values[successor]
                elem = successor
            }

            fin child = if self.left[elem] >= 0 {
                self.left[elem]
            } else {
                self.right[elem]
            }
            fin oldParent = self.parent[elem]
            self.replaceParentChild(oldParent, elem, child)
            self.releaseNode(elem)
            self.rebalanceFrom(oldParent)
            return previous
        }

        confine func entrySnapshot(): Array<MapEntry<K, V>> { ref self ->
            var result: Array<MapEntry<K, V>> = Array::fill<MapEntry<K, V>>(self._size)
            fin stack = alloc Int[self._size]
            var stackSize = 0
            var elem = self.root
            var output = 0
            while elem >= 0 || stackSize > 0 {
                while elem >= 0 {
                    stack[stackSize] = elem
                    stackSize += 1
                    elem = self.left[elem]
                }
                stackSize -= 1
                elem = stack[stackSize]
                result[output] = MapEntry(self.keys[elem], self.values[elem])
                output += 1
                elem = self.right[elem]
            }
            drop stack
            return result
        }
    }

    impl Map<K, V> for TreeMap<K, V> {
        prop size: Int = self._size
        prop isEmpty: Bool = self._size == 0
        prop isNotEmpty: Bool = self._size > 0

        func containsKey(key: ref K): Bool { ref self ->
            return self.findNode(key) >= 0
        }

        func containsValue(value: ref V): Bool { ref self ->
            fin all = self.entrySnapshot()
            for i in 0..<all.size {
                if all[i].value == value { return true }
            }
            return false
        }

        func get(key: ref K): V? { ref self ->
            fin elem = self.findNode(key)
            if elem < 0 { return null }
            return self.values[elem]
        }

        func getOrDefault(key: ref K, defaultValue: V): V { ref self ->
            fin elem = self.findNode(key)
            if elem < 0 { return defaultValue }
            return self.values[elem]
        }

        func entries(): Array<MapEntry<K, V>> { ref self -> return self.entrySnapshot() }

        func keys(): List<K> { ref self ->
            fin all = self.entries()
            var result: Array<K> = Array::fill<K>(all.size)
            for i in 0..<all.size {
                result[i] = all[i].key
            }
            return result
        }

        func values(): List<V> { ref self ->
            fin all = self.entrySnapshot()
            var result: Array<V> = Array::fill<V>(all.size)
            for i in 0..<all.size {
                result[i] = all[i].value
            }
            return result
        }

        func forEach(action: (ref K, ref V) -> Unit) { ref self ->
            fin all = self.entrySnapshot()
            for i in 0..<all.size {
                action(all[i].key, all[i].value)
            }
        }
    }

    impl MutableMap<K, V> for TreeMap<K, V> {
        func put(key: K, value: V): V? { mut ref self ->
            return self.putValue(key, value)
        }

        func putAll(other: ref Map<K, V>) { mut ref self ->
            fin all = other.entries()
            for i in 0..<all.size {
                self.putValue(all[i].key, all[i].value)
            }
        }

        func remove(key: ref K): V? { mut ref self -> return self.removeValue(key) }

        func clear() { mut ref self ->
            self.root = -1
            self.freeHead = -1
            self.elemCount = 0
            self._size = 0
        }

        func getOrPut(key: K, defaultValue: () -> V): V { mut ref self ->
            fin elem = self.findNode(key)
            if elem >= 0 { return self.values[elem] }
            fin value = defaultValue()
            self.putValue(key, value)
            return value
        }
    }

    impl SortedMap<K, V> for TreeMap<K, V> {
        func firstKey(): K? { ref self ->
            fin elem = self.minimumNode(self.root)
            if elem < 0 { return null }
            return self.keys[elem]
        }

        func lastKey(): K? { ref self ->
            fin elem = self.maximumNode(self.root)
            if elem < 0 { return null }
            return self.keys[elem]
        }

        func lowerKey(key: ref K): K? { ref self ->
            var elem = self.root
            var candidate = -1
            while elem >= 0 {
                if self.keys[elem] < key {
                    candidate = elem
                    elem = self.right[elem]
                } else {
                    elem = self.left[elem]
                }
            }
            if candidate < 0 { return null }
            return self.keys[candidate]
        }

        func floorKey(key: ref K): K? { ref self ->
            fin exact = self.findNode(key)
            if exact >= 0 { return self.keys[exact] }
            return self.lowerKey(key)
        }

        func ceilingKey(key: ref K): K? { ref self ->
            fin exact = self.findNode(key)
            if exact >= 0 { return self.keys[exact] }
            return self.higherKey(key)
        }

        func higherKey(key: ref K): K? { ref self ->
            var elem = self.root
            var candidate = -1
            while elem >= 0 {
                if key < self.keys[elem] {
                    candidate = elem
                    elem = self.left[elem]
                }
                else {
                    elem = self.right[elem]
                }
            }
            if candidate < 0 { return null }
            return self.keys[candidate]
        }

        func firstEntry(): MapEntry<K, V>? { ref self ->
            fin elem = self.minimumNode(self.root)
            if elem < 0 { return null }
            return MapEntry(self.keys[elem], self.values[elem])
        }

        func lastEntry(): MapEntry<K, V>? { ref self ->
            fin elem = self.maximumNode(self.root)
            if elem < 0 { return null }
            return MapEntry(self.keys[elem], self.values[elem])
        }

        func headMap(toKey: ref K, inclusive: Bool = false): SortedMap<K, V> { ref self ->
            var result = TreeMap<K, V>()
            fin all = self.entrySnapshot()
            for i in 0..<all.size {
                fin beforeEnd = all[i].key < toKey || (inclusive && !(toKey < all[i].key))
                if beforeEnd { result.put(all[i].key, all[i].value) }
            }
            return result
        }

        func tailMap(fromKey: ref K, inclusive: Bool = true): SortedMap<K, V> { ref self ->
            var result = TreeMap<K, V>()
            fin all = self.entrySnapshot()
            for i in 0..<all.size {
                fin afterStart = fromKey < all[i].key || (inclusive && !(all[i].key < fromKey))
                if afterStart { result.put(all[i].key, all[i].value) }
            }
            return result
        }

        func subMap(fromKey: ref K, fromInclusive: Bool, toKey: ref K, toInclusive: Bool): SortedMap<K, V> { ref self ->
            assert !(toKey < fromKey) { "subMap start must not be greater than end" }
            var result = TreeMap<K, V>()
            fin all = self.entrySnapshot()
            for i in 0..<all.size {
                fin afterStart = fromKey < all[i].key || (fromInclusive && !(all[i].key < fromKey))
                fin beforeEnd = all[i].key < toKey || (toInclusive && !(toKey < all[i].key))
                if afterStart && beforeEnd { result.put(all[i].key, all[i].value) }
            }
            return result
        }
    }

    impl MutableSortedMap<K, V> for TreeMap<K, V> {
        func pollFirstEntry(): MapEntry<K, V>? { mut ref self ->
            fin elem = self.minimumNode(self.root)
            if elem < 0 { return null }
            fin result = MapEntry(self.keys[elem], self.values[elem])
            self.removeValue(self.keys[elem])
            return result
        }

        func pollLastEntry(): MapEntry<K, V>? { mut ref self ->
            fin elem = self.maximumNode(self.root)
            if elem < 0 { return null }
            fin result = MapEntry(self.keys[elem], self.values[elem])
            self.removeValue(self.keys[elem])
            return result
        }
    }

