    /** Slicing is over current iteration order and returns an ordered snapshot. */
    @Experimental(sinceAzora: "0.0.4")
    impl oper[:] by MapSlice for HashMap<K, V> { ref self, slice ->
        assert slice.step != 0 { "Map slice step cannot be zero" }
        fin all = self.entries()
        var result = LinkedHashMap<K, V>()
        var i = slice.start
        while (slice.step > 0 && i < slice.end) || (slice.step < 0 && i > slice.end) {
            if i >= 0 && i < all.size {
                result.put(all[i].key, all[i].value)
            }
            i += slice.step
        }
        return result
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper[:] by MapSlice for LinkedHashMap<K, V> { ref self, slice ->
        assert slice.step != 0 { "Map slice step cannot be zero" }
        var result = LinkedHashMap<K, V>()
        var i = slice.start
        while (slice.step > 0 && i < slice.end) || (slice.step < 0 && i > slice.end) {
            if i >= 0 && i < self._size {
                result.put(self.keys[i], self.values[i])
            }
            i += slice.step
        }
        return result
    }

