use friend zone std {
    /**
     * Builds an immutable [Map].
     *
     * @0 `map![]` expands to `std::emptyMap()`.
     * @1 `map!["One": 1, "Two": 2]` expands to `std::mapOf("One" to 1, "Two" to 2)`. // todo. to infx like in Kotlin
     */
    meta map {
        [] => std::emptyMap()
        [...${key: value}] => std::mapOf(...std::mapEntry($key, $value))
    }

    /**
     * Builds an mutable [Map].
     *
     * @0 `mut map![]` expands to `std::emptyMutableMap()`.
     * @1 `mut map!["One": 1, "Two": 2]` expands to `std::mutableMapOf("One" to 1, "Two" to 2)`.
     */
    meta mut map {
        [] => std::emptyMutableMap()
        [...${key: value}] => std::mutableMapOf(...std::mapEntry($key, $value))
    }

    /**
     * Builds a hash [Map].
     *
     * @0 `# map![]` expands to `std::emptyHashMap()`.
     * @1 `# map!["One": 1, "Two": 2]` expands to `std::hashMapOf("One" to 1, "Two" to 2)`.
     */
    meta # map {
        [] => std::emptyHashMap()
        [...${key: value}] => std::hashMapOf(...std::mapEntry($key, $value))
    }

    /**
     * Builds a linked hash [Map].
     *
     * @0 `!# map![]` expands to `std::emptyLinkedHashMap()`.
     * @1 `!# map!["One": 1, "Two": 2]` expands to `std::linkedHashMapOf("One" to 1, "Two" to 2)`.
     */
    meta !# map {
        [] => std::emptyLinkedHashMap()
        [...${key: value}] => std::linkedHashMapOf(...std::mapEntry($key, $value))
    }

    /**
     * Builds a tree [Map].
     *
     * @0 `^ map![]` expands to `std::emptyTreeMap()`.
     * @1 `^ map!["One": 1, "Two": 2]` expands to `std::treeMapOf("One" to 1, "Two" to 2)`.
     */
    meta ^ map {
        [] => std::emptyTreeMap()
        [...$items] => std::treeMapOf(...$items)
    }

    meta type {
        [K: V] => std::Map<K, V>
        mut [K: V] => std::MutableMap<K, V>
        # [K: V] => std::HashMap<K, V>
        !# [K: V] => std::LinkedHashMap<K, V>
        ^ [K: V] => std::TreeMap<K, V>
    }
}

test "hash map stores and retrieves by key" {
    var m = HashMap<Int, String>()
    m.put(1, "a")
    m.put(2, "b")
    assert m.size == 2 { "hash map size changed" }
    assert m.get(1) == "a" && m.get(2) == "b" { "hash map retrieval changed" }
    assert m.containsKey(2) && !m.containsKey(9) { "hash map containsKey changed" }
}

test "hash map put replaces existing keys" {
    var m = HashMap<Int, String>()
    m.put(1, "a")
    m.put(1, "b")
    assert m.size == 1 && m.get(1) == "b" { "put must replace, not insert" }
}

test "hash map remove and clear drop entries" {
    var m = HashMap<Int, String>()
    m.put(1, "a")
    m.put(2, "b")
    m.remove(1)
    assert m.size == 1 && !m.containsKey(1) { "remove must drop the entry" }
    m.clear()
    assert m.isEmpty { "clear must empty the map" }
}

test "hash map containsValue and getOrDefault" {
    var m = HashMap<Int, String>()
    m.put(1, "a")
    assert m.containsValue("a") && !m.containsValue("z") { "containsValue changed" }
    assert m.getOrDefault(1, "z") == "a" { "getOrDefault must return the stored value" }
    assert m.getOrDefault(9, "z") == "z" { "getOrDefault must return the default" }
}

test "hash map index operators read and write" {
    var m = HashMap<Int, String>()
    m[1] = "a"
    m[2] = "b"
    assert m.size == 2 && m[1] == "a" && m[2] == "b" { "index operators changed" }
}

test "linked hash map preserves insertion order" {
    var m = LinkedHashMap<Int, String>()
    m.put(3, "c")
    m.put(1, "a")
    m.put(2, "b")
    fin keys = m.keys()
    assert keys.size == 3 && keys.get(0) == 3 && keys.get(1) == 1 && keys.get(2) == 2 { "linked hash map order changed" }
}

test "tree map keeps keys sorted" {
    var m = TreeMap<Int, String>()
    m.put(3, "c")
    m.put(1, "a")
    m.put(2, "b")
    fin keys = m.keys()
    assert keys.size == 3 && keys.get(0) == 1 && keys.get(1) == 2 && keys.get(2) == 3 { "tree map sort order changed" }
}

test "tree map navigation finds neighbors" {
    var m = TreeMap<Int, String>()
    m.put(1, "a")
    m.put(3, "c")
    m.put(5, "e")
    assert m.firstKey() == 1 && m.lastKey() == 5 { "tree map extrema changed" }
    assert m.lowerKey(3) == 1 { "lowerKey changed" }
    assert m.higherKey(3) == 5 { "higherKey changed" }
    assert m.floorKey(3) == 3 { "floorKey changed" }
    assert m.ceilingKey(3) == 3 { "ceilingKey changed" }
}

test "tree map polling removes the extremes" {
    var m = TreeMap<Int, String>()
    m.put(1, "a")
    m.put(2, "b")
    m.put(3, "c")
    m.pollFirstEntry()
    m.pollLastEntry()
    assert m.size == 1 && m.firstKey() == 2 { "polling must leave only the middle" }
}

test "factories build maps from entries" {
    fin hm = std::hashMapOf(1 to "a", 2 to "b")
    fin lhm = std::linkedHashMapOf(1 to "a", 2 to "b")
    fin tm = std::treeMapOf(1 to "a", 2 to "b")
    assert hm.size == 2 && lhm.size == 2 && tm.size == 2 { "factory sizes changed" }
    assert hm.get(1) == "a" && lhm.get(2) == "b" && tm.get(1) == "a" { "factory retrieval changed" }
}

test "mapOf exposes a read-only Map" {
    fin m = std::mapOf(1 to "a", 2 to "b")
    assert m.size == 2 { "mapOf size changed" }
    assert m.containsKey(1) && m.get(1) == "a" { "mapOf must store entries read-only" }
}

test "mutableMapOf allows in-place mutation" {
    var m = std::mutableMapOf(1 to "a")
    m.put(2, "b")
    m.remove(1)
    assert m.size == 1 && m.get(2) == "b" { "mutableMapOf mutation changed" }
}

test "map plus and minus derive new maps" {
    var origin = HashMap<Int, String>()
    origin.put(1, "a")
    fin grown = origin + (2 to "b")
    fin shrunk = origin - 1
    assert grown.size == 2 && grown.get(2) == "b" { "oper+ must add the entry" }
    assert shrunk.size == 0 { "oper- must remove the key" }
    assert origin.size == 1 { "derivation must not mutate the source" }
}

test "map equality compares entries not identity" {
    var a = HashMap<Int, String>()
    a.put(1, "a")
    var b = HashMap<Int, String>()
    b.put(1, "a")
    assert a == b { "maps with equal entries must be equal" }
    b.put(2, "b")
    assert a != b { "differing maps must be unequal" }
}

