module std.container.set

import std.serializer
import std.convert

/**
 * @file std/container/set
 *
 * Proposed native set hierarchy for Azora, mirroring `map.az` and `list.az`.
 *
 * Sets come in two flavors:
 *
 * - `Set<T>` is the read-only view: membership tests, algebra (`union`,
 *   `intersect`, `difference`), and functional combinators returning fresh
 *   `Set<T>` snapshots.
 * - `MutableSet<T>` adds in-place mutation. Every mutation receives
 *   `mut ref self`, so a caller holding only a shared `ref Set<T>` view
 *   cannot mutate it.
 *
 * `LinkedHashSet<T>` is the single concrete pack implementing both specs. It
 * stores unique elements in insertion order, so indexed access is stable. The
 * `setOf`, `mutableSetOf`, `emptySet`, and `linkedHashSetOf` factories
 * construct it; `setOf` and `emptySet` expose the read-only `Set<T>` view,
 * `mutableSetOf` exposes `MutableSet<T>`.
 *
 * @since 0.0.4
 */

friend zone std {
    /**
     * Read-only behavior shared by every set implementation.
     *
     * `Set` stores unique elements. A concrete pack defines the iteration
     * order; `LinkedHashSet` uses insertion order, which makes indexed access
     * well-defined.
     *
     * @param T The element type.
     */
    @Experimental(sinceAzora: "0.0.4")
    spec Set<T> {
        /** Number of unique elements. */
        prop size: Int

        /** Whether this set has no elements. */
        prop isEmpty: Bool

        /** Whether this set has at least one element. */
        prop isNotEmpty: Bool

        /** Returns the element at `index` in iteration order. Asserts out of bounds. */
        func get(index: Int): T

        /** Returns whether `element` is present. */
        func contains(element: T): Bool

        /** Invokes `action` once for every element in iteration order. */
        func forEach(action: (T) -> Unit)

        /** Returns a new set with only elements satisfying `predicate`. */
        func filter(predicate: (T) -> Bool): Set<T>

        /** Returns whether at least one element satisfies `predicate`. */
        func any(predicate: (T) -> Bool): Bool

        /** Returns whether every element satisfies `predicate`. */
        func all(predicate: (T) -> Bool): Bool

        /** Returns a new set with all unique elements from both sets. */
        func union(other: Set<T>): Set<T>

        /** Returns a new set with only elements present in both sets. */
        func intersect(other: Set<T>): Set<T>

        /** Returns a new set with elements here that are absent from `other`. */
        func difference(other: Set<T>): Set<T>
    }

    /**
     * Mutation behavior implemented by mutable set packs.
     *
     * Mutation always receives `mut ref self`. Implementing this spec does not
     * weaken a `ref Set<T>` view: callers holding only a shared reference can
     * still use only read operations.
     *
     * @param T The element type.
     */
    @Experimental(sinceAzora: "0.0.4")
    spec MutableSet<T> : Set<T> {
        /** Adds `element`; returns whether membership changed. */
        func add(element: T): Bool

        /** Removes `element`; returns whether membership changed. */
        func remove(element: T): Bool

        /** Removes every element while retaining reusable internal capacity. */
        func clear()
    }

    /**
     * Hash set pack backing both `Set<T>` and `MutableSet<T>`.
     *
     * Stores unique elements in insertion order in a contiguous `T*` buffer
     * that doubles on demand. Uniqueness and equality use `oper==` for `T`.
     * Fields are `shield` so external zones cannot reach into the buffer.
     *
     * @param T The element type.
     */
    @Experimental(sinceAzora: "0.0.4")
    @Serializable
    pack<T> LinkedHashSet {
        shield var data: T* = alloc T[8]
        shield var size: Int = 0
        shield var capacity: Int = 8
    }

    // ---------------------------------------------------------------------
    // LinkedHashSet implementation
    // ---------------------------------------------------------------------

    impl LinkedHashSet<T> {
        /** Doubles the backing buffer, copying existing elements. */
        @Experimental(sinceAzora: "0.0.4")
        func growSet() { mut ref self ->
            fin newCap = self.capacity * 2
            fin newData = alloc T[newCap]
            for i in 0..<self.size {
                newData[i] = self.data[i]
            }
            fin oldData = self.data
            self.data = newData
            self.capacity = newCap
            drop oldData
        }

        /** Returns whether `element` is already stored. */
        @Experimental(sinceAzora: "0.0.4")
        confine func has(element: T): Bool { ref self ->
            for i in 0..<self.size {
                if self.data[i] == element { return true }
            }
            return false
        }
    }

    impl Set<T> for LinkedHashSet<T> {
        prop size: Int = self.size
        prop isEmpty: Bool = self.size == 0
        prop isNotEmpty: Bool = self.size > 0

        func get(index: Int): T { ref self ->
            assert index >= 0 { "Set index must be non-negative" }
            assert index < self.size { "Set index out of bounds" }
            return self.data[index]
        }

        func contains(element: T): Bool { ref self ->
            return self.has(element)
        }

        func forEach(action: (T) -> Unit) { ref self ->
            for i in 0..<self.size {
                action(self.data[i])
            }
        }

        func filter(predicate: (T) -> Bool): Set<T> { ref self ->
            var result = LinkedHashSet<T>()
            for i in 0..<self.size {
                if predicate(self.data[i]) {
                    result.add(self.data[i])
                }
            }
            return result
        }

        func any(predicate: (T) -> Bool): Bool { ref self ->
            for i in 0..<self.size {
                if predicate(self.data[i]) { return true }
            }
            return false
        }

        func all(predicate: (T) -> Bool): Bool { ref self ->
            for i in 0..<self.size {
                if !predicate(self.data[i]) { return false }
            }
            return true
        }

        func union(other: Set<T>): Set<T> { ref self ->
            var result = LinkedHashSet<T>()
            for i in 0..<self.size {
                result.add(self.data[i])
            }
            for j in 0..<other.size {
                result.add(other.get(j))
            }
            return result
        }

        func intersect(other: Set<T>): Set<T> { ref self ->
            var result = LinkedHashSet<T>()
            for i in 0..<self.size {
                if other.contains(self.data[i]) {
                    result.add(self.data[i])
                }
            }
            return result
        }

        func difference(other: Set<T>): Set<T> { ref self ->
            var result = LinkedHashSet<T>()
            for i in 0..<self.size {
                if !other.contains(self.data[i]) {
                    result.add(self.data[i])
                }
            }
            return result
        }
    }

    impl MutableSet<T> for LinkedHashSet<T> {
        func add(element: T): Bool { mut ref self ->
            if self.has(element) { return false }
            if self.size >= self.capacity { self.growSet() }
            self.data[self.size] = element
            self.size = self.size + 1
            return true
        }

        func remove(element: T): Bool { mut ref self ->
            var idx = -1
            for i in 0..<self.size {
                if self.data[i] == element { idx = i }
            }
            if idx < 0 { return false }
            for j in idx..<self.size - 1 {
                self.data[j] = self.data[j + 1]
            }
            self.size = self.size - 1
            return true
        }

        func clear() { mut ref self ->
            fin oldData = self.data
            self.data = alloc T[8]
            self.size = 0
            self.capacity = 8
            drop oldData
        }
    }

    // ---------------------------------------------------------------------
    // Factories
    // ---------------------------------------------------------------------

    @Experimental(sinceAzora: "0.0.4")
    func<T> emptySet(): Set<T> {
        return LinkedHashSet<T>()
    }

    @Experimental(sinceAzora: "0.0.4")
    func<T> emptyMutableSet(): MutableSet<T> {
        return LinkedHashSet<T>()
    }

    @Experimental(sinceAzora: "0.0.4")
    func<T> setOf(...elements: T): Set<T> {
        var result = LinkedHashSet<T>()
        for i in 0..<elements.size {
            result.add(elements[i])
        }
        return result
    }

    @Experimental(sinceAzora: "0.0.4")
    func<T> mutableSetOf(...elements: T): MutableSet<T> {
        var result = LinkedHashSet<T>()
        for i in 0..<elements.size {
            result.add(elements[i])
        }
        return result
    }

    @Experimental(sinceAzora: "0.0.4")
    func<T> linkedHashSetOf(...elements: T): LinkedHashSet<T> {
        var result = LinkedHashSet<T>()
        for i in 0..<elements.size {
            result.add(elements[i])
        }
        return result
    }

    @Experimental(sinceAzora: "0.0.4")
    func<T> emptyLinkedHashSet(): MutableSet<T> {
        return LinkedHashSet<T>()
    }

    // --- HashSet (hash-table, unspecified iteration order; T requires oper# + oper==) ---

    @Experimental(sinceAzora: "0.0.4")
    @Serializable
    pack<T> HashSet {
        shield var data: T* = alloc T[8]
        shield var size: Int = 0
        shield var capacity: Int = 8
    }

