            return self.data[index]
        }

        func contains(element: T): Bool { ref self ->
            return self.has(element)
        }

        func forEach(action: (T) -> Unit) { ref self ->
            for i in 0..<self.size {
                action(self.data[i])
            }
        }

        func filter(predicate: (T) -> Bool): Set<T> { ref self ->
            var result = TreeSet<T>()
            for i in 0..<self.size {
                if predicate(self.data[i]) {
                    result.add(self.data[i])
                }
            }
            return result
        }

        func any(predicate: (T) -> Bool): Bool { ref self ->
            for i in 0..<self.size {
                if predicate(self.data[i]) { return true }
            }
            return false
        }

        func all(predicate: (T) -> Bool): Bool { ref self ->
            for i in 0..<self.size {
                if !predicate(self.data[i]) { return false }
            }
            return true
        }

        func union(other: Set<T>): Set<T> { ref self ->
            var result = TreeSet<T>()
            for i in 0..<self.size {
                result.add(self.data[i])
            }
            var j = 0
            while j < other.size {
                result.add(other.get(j))
                j += 1
            }
            return result
        }

        func intersect(other: Set<T>): Set<T> { ref self ->
            var result = TreeSet<T>()
            for i in 0..<self.size {
                if other.contains(self.data[i]) {
                    result.add(self.data[i])
                }
            }
            return result
        }

        func difference(other: Set<T>): Set<T> { ref self ->
            var result = TreeSet<T>()
            for i in 0..<self.size {
                if !other.contains(self.data[i]) {
                    result.add(self.data[i])
                }
            }
            return result
        }
    }

    impl MutableSet<T> for TreeSet<T> {
        func add(element: T): Bool { mut ref self ->
            if self.has(element) { return false }
            if self.size >= self.capacity { self.growSet() }
            self.data[self.size] = element
            self.size = self.size + 1
            return true
        }

        func remove(element: T): Bool { mut ref self ->
            var idx = -1
            for i in 0..<self.size {
                if self.data[i] == element { idx = i }
            }
            if idx < 0 { return false }
            var j = idx
            while j < self.size - 1 {
                self.data[j] = self.data[j + 1]
                j += 1
            }
            self.size = self.size - 1
            return true
        }

        func clear() { mut ref self ->
            fin oldData = self.data
            self.data = alloc T[8]
            self.size = 0
            self.capacity = 8
            drop oldData
        }
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper[] for TreeSet<T> { ref self, index ->
        assert index >= 0 && index < self.size {
            "Set index out of bounds"
        }
        return self.data[index]
    }

    @Experimental(sinceAzora: "0.0.4")
    impl Into<String> for TreeSet<T> { ref self ->
        var s = "{"
        for i in 0..<self.size {
            if i > 0 { s = s + ", " }
            s = s + std::convert::toString(self.data[i])
        }
        return s + "}"
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper== by Set<T> for TreeSet<T> { ref self, rhs ->
        if self.size != rhs.size { return false }
        for i in 0..<self.size {
            if !rhs.contains(self.data[i]) { return false }
        }
        return true
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper!= by Set<T> for TreeSet<T> { ref self, rhs ->
        return !(self == rhs)
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper# for TreeSet<T> { ref self ->
        var result = 0 as ULong
        for i in 0..<self.size {
            result = result + #self.data[i]
        }
        return result
    }

    // ---------------------------------------------------------------------
    // Operators
    // ---------------------------------------------------------------------

    @Experimental(sinceAzora: "0.0.4")
    impl oper[] for LinkedHashSet<T> { ref self, index ->
        assert index >= 0 && index < self.size {
            "Set index out of bounds"
        }
        return self.data[index]
    }

    @Experimental(sinceAzora: "0.0.4")
    impl Into<String> for LinkedHashSet<T> { ref self ->
        var s = "{"
        for i in 0..<self.size {
            if i > 0 { s = s + ", " }
            s = s + std::convert::toString(self.data[i])
        }
        return s + "}"
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper== by Set<T> for LinkedHashSet<T> { ref self, rhs ->
        if self.size != rhs.size { return false }
        for i in 0..<self.size {
            if !rhs.contains(self.data[i]) { return false }
        }
        return true
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper!= by Set<T> for LinkedHashSet<T> { ref self, rhs ->
        return !(self == rhs)
    }

    @Experimental(sinceAzora: "0.0.4")
    impl oper# for LinkedHashSet<T> { ref self ->
        var result = 0 as ULong
        for i in 0..<self.size {
            result = result + #self.data[i]
        }
        return result
    }
}

use friend zone std {
    /**
     * Builds an immutable [Set].
     *
     * @0 `set![]` expands to `std::emptySet()`.
     * @1 `set![1, 2, 3]` expands to `std::setOf(1, 2, 3)`.
     */
    meta set {
        [] => std::emptySet()
        [...$items] => std::setOf(...$items)
    }

    /**
     * Builds an mutable [Set].
     *
     * @0 `mut set![]` expands to `std::emptyMutableSet()`.
     * @1 `mut set![1, 2, 3]` expands to `std::mutableSetOf(1, 2, 3)`.
     */
    meta mut set {
        [] => std::emptyMutableSet()
        [...$items] => std::mutableSetOf(...$items)
    }

    /**
     * Builds a hash [Set].
     *
     * @0 `# set![]` expands to `std::emptyHashSet()`.
     * @1 `# set![1, 2, 3]` expands to `std::hashSetOf(1, 2, 3)`.
     */
    meta # set {
        [] => std::emptyHashSet()
        [...$items] => std::hashSetOf(...$items)
    }

    /**
     * Builds a linked hash [Set].
     *
     * @0 `!# set![]` expands to `std::emptyLinkedHashSet()`.
     * @1 `!# set![1, 2, 3]` expands to `std::linkedHashSetOf(1, 2, 3)`.
     */
    meta !# set {
        [] => std::emptyLinkedHashSet()
        [...$items] => std::linkedHashSetOf(...$items)
    }

    /**
     * Builds a tree [Set].
     *
     * @0 `^ set![]` expands to `std::emptyTreeSet()`.
     * @1 `^ set![1, 2, 3]` expands to `std::treeSetOf(1, 2, 3)`.
     */
    meta ^ set {
        [] => std::emptyTreeSet()
        [...$items] => std::treeSetOf(...$items)
    }

    meta type {
        {T} => std::Set<T>
        mut {T} => std::MutableSet<T>
        # {T} => std::HashSet<T>
        !# {T} => std::LinkedHashSet<T>
        ^ {T} => std::TreeSet<T>
    }
}

test "set starts empty" {
    fin value = std::emptySet<Int>()
    assert value.size == 0 && value.isEmpty { "emptySet must contain no values" }
}

test "setOf removes duplicates" {
    fin value = std::setOf(1, 2, 1, 3, 2)
    assert value.size == 3 { "setOf must retain unique values only" }
    assert value.get(0) == 1 && value.get(1) == 2 && value.get(2) == 3 { "set insertion order changed" }
}

test "mutableSetOf removes duplicates" {
    fin value = std::mutableSetOf(1, 2, 1)
    assert value.size == 2 && value.contains(1) && value.contains(2) { "mutableSetOf uniqueness changed" }
}

test "set add reports whether membership changed" {
    var value = std::mutableSetOf(1)
    assert !value.add(1) { "adding a duplicate must be a no-op" }
    assert value.add(2) { "adding a new value must report a change" }
    assert value.size == 2 { "set size must count unique values" }
}

test "set remove preserves remaining membership" {
    var value = std::mutableSetOf(1, 2, 3)
    assert value.remove(2) { "remove must report an existing value" }
    assert !value.remove(9) { "remove must report a missing value" }
    assert value.size == 2 && !value.contains(2) { "removed values must disappear" }
}

test "set algebra produces unique results" {
    fin left = std::setOf(1, 2, 3)
    fin right = std::setOf(3, 4)
    fin union = left.union(right)
    fin common = left.intersect(right)
    fin difference = left.difference(right)
    assert union.size == 4 && union.contains(4) { "union must contain both memberships" }
    assert common.size == 1 && common.contains(3) { "intersection must contain shared values" }
    assert difference.size == 2 && difference.contains(1) && difference.contains(2) { "difference must exclude right values" }
}

test "set grows without losing uniqueness" {
    var value = LinkedHashSet<Int>()
    for i in 0..<20 {
        value.add(i % 10)
    }
    assert value.size == 10 && value.contains(9) { "growth must preserve ten unique values" }
}

test "set clear permits reuse" {
    var value = std::mutableSetOf(1, 2)
    value.clear()
    value.add(7)
    assert value.size == 1 && value.contains(7) { "cleared sets must remain reusable" }
}

test "set serialization metadata is declared" {
    inline assert (std::reflect<LinkedHashSet>).hasDeco<Serializable> { "LinkedHashSet must carry Serializable metadata" }
}

test .All "set"

