friend zone std::math {
    /**
     * The ratio of a circle's circumference to its diameter.
     */
    @SinceAzora("0.0.1")
    fin PI: Real = 3.14159265358979

    /**
     * Euler's number, the base of natural logarithms.
     */
    @SinceAzora("0.0.1")
    fin E: Real = 2.71828182845905

    /**
     * The ratio of a circle's circumference to its radius (2 * PI).
     */
    @SinceAzora("0.0.1")
    fin TAU: Real = 6.28318530717959

    /**
     * The square root of 2.
     */
    @SinceAzora("0.0.1")
    fin SQRT2: Real = 1.41421356237310

    /**
     * The golden ratio (phi).
     */
    @SinceAzora("0.0.1")
    fin PHI: Real = 1.61803398874989

    /**
     * Positive infinity representation.
     */
    @SinceAzora("0.0.1")
    fin INF: Real = 1.0 / 0.0

    /**
     * The smallest positive real value.
     */
    @SinceAzora("0.0.1")
    fin EPSILON: Real = 0.00000000000001

    /**
     * Returns the absolute value of the given number.
     *
     * @param x The value to take the absolute value of.
     * @return The non-negative magnitude of x.
     */
    @Experimental(sinceAzora: "0.0.1")
    func abs<T>(x: T): T
    out {
        assert it >= 0 { "abs must return non-negative" }
    } zone {
        return if x < 0 { -x } else { x }
    }

    /**
     * Returns the smaller of two values.
     *
     * @param a The first value to compare.
     * @param b The second value to compare.
     * @return The lesser of a and b.
     */
    @Experimental(sinceAzora: "0.0.1")
    func min<T>(a: T, b: T): T {
        return if a < b { a } else { b }
    }

    /**
     * Returns the larger of two values.
     *
     * @param a The first value to compare.
     * @param b The second value to compare.
     * @return The greater of a and b.
     */
    @Experimental(sinceAzora: "0.0.1")
    func max<T>(a: T, b: T): T {
        return if a > b { a } else { b }
    }

    /**
     * Constrains a value within the given range.
     *
     * @param x The value to clamp.
     * @param lo The lower bound of the range.
     * @param hi The upper bound of the range.
     * @return x if it falls within [lo, hi], otherwise the nearest bound.
     */
    @Experimental(sinceAzora: "0.0.1")
    func clamp<T>(x: T, lo: T, hi: T): T
    in {
        assert lo <= hi { "clamp lower bound must be <= upper bound" }
    } zone {
        return max<T>(lo, min<T>(x, hi))
    }

    /**
     * Returns the sign of a number as an integer.
     *
     * @param x The value to determine the sign of.
     * @return 1 if x is positive, -1 if negative, 0 if zero.
     */
    @Experimental(sinceAzora: "0.0.1")
    func sign<T>(x: T): Int {
        return if x > 0 { 1 } else { if x < 0 { -1 } else { 0 } }
    }

    /**
     * Performs linear interpolation between two values.
     *
     * @param a The start value.
     * @param b The end value.
     * @param t The interpolation factor, typically in [0.0, 1.0].
     * @return The interpolated value a + (b - a) * t.
     */
    @Experimental(sinceAzora: "0.0.1")
    func lerp(a: Real, b: Real, t: Real): Real
    in {
        assert t >= 0.0 { "lerp factor must be >= 0.0" }
        assert t <= 1.0 { "lerp factor must be <= 1.0" }
    } zone {
        return a + (b - a) * t
    }

    /**
     * Returns the floor of a real number (largest integer <= x).
     *
     * @param x The value.
     * @return The floor value as an integer.
     */
    @Experimental(sinceAzora: "0.0.1")
    func floor(x: Real): Int {
        fin i = x as Int
        return if x < 0.0 && x != (i as Real) { i - 1 } else { i }
    }

    /**
     * Returns the ceiling of a real number (smallest integer >= x).
     *
     * @param x The value.
     * @return The ceiling value as an integer.
     */
    @Experimental(sinceAzora: "0.0.1")
    func ceil(x: Real): Int {
        fin i = x as Int
        return if x > 0.0 && x != (i as Real) { i + 1 } else { i }
    }

    /**
     * Rounds a real number to the nearest integer.
     *
     * @param x The value.
     * @return The rounded value.
     */
    @Experimental(sinceAzora: "0.0.1")
    func round(x: Real): Int {
        return floor(x + 0.5)
    }

    /**
     * Returns the fractional part of a real number.
     *
     * @param x The value.
     * @return The fractional part (x - floor(x)).
     */
    @Experimental(sinceAzora: "0.0.1")
    func frac(x: Real): Real {
        return x - (floor(x) as Real)
    }

    /**
     * Maps a value from one range to another.
     *
     * @param x The value to map.
     * @param inMin The input range minimum.
     * @param inMax The input range maximum.
     * @param outMin The output range minimum.
     * @param outMax The output range maximum.
     * @return The mapped value.
     */
    @Experimental(sinceAzora: "0.0.1")
    func mapRange(x: Real, inMin: Real, inMax: Real, outMin: Real, outMax: Real): Real
    in {
        assert inMax != inMin { "Input range must not be zero-width" }
    } zone {
        return outMin + (x - inMin) * (outMax - outMin) / (inMax - inMin)
    }

    /**
     * Checks if two real numbers are approximately equal.
     *
     * @param a The first value.
     * @param b The second value.
     * @param epsilon The tolerance (default: 0.00000001).
     * @return true if |a - b| < epsilon.
     */
    @Experimental(sinceAzora: "0.0.1")
    func approxEqual(a: Real, b: Real, epsilon: Real): Bool
    in {
        assert epsilon > 0.0 { "epsilon must be positive" }
    } zone {
        var diff = a - b
        if diff < 0.0 { diff = -diff }
        return diff < epsilon
    }

    /**
     * Computes exponentiation.
     *
     * @param value The base value.
     * @param exp The exponent (must be non-negative).
     * @return value raised to the power of exp.
     */
    @Experimental(sinceAzora: "0.0.1")
    func pow<T>(value: T, exp: Int): T
    in {
        assert exp >= 0 { "Exponent must be non-negative" }
    } zone {
        if exp == 0 { return 1 }
        var result = value
        for i in 1..<exp {
            result = result * value
        }
        return result
    }

    /**
     * Computes the factorial of n.
     *
     * @param n The non-negative integer.
     * @return n! (n factorial).
     */
    @Experimental(sinceAzora: "0.0.1")
    func factorial<T>(n: T): T
    in {
        assert n >= 0 { "Factorial requires non-negative input" }
    } out {
        assert it >= 1 { "Factorial result must be >= 1" }
    } zone {
        if n <= 1 { return 1 }
        var result = 1
        var i = 2
        while i <= n {
            result = result * i
            i += 1
        }
        return result
    }

    /**
     * Computes the greatest common divisor using the Euclidean algorithm.
     *
     * @param a The first integer.
     * @param b The second integer.
     * @return The GCD of a and b.
     */
    @Experimental(sinceAzora: "0.0.1")
    func gcd<T>(a: T, b: T): T
    out {
        assert it >= 0 { "GCD must be non-negative" }
    } zone {
        var x = a
        if x < 0 { x = -x }
        var y = b
        if y < 0 { y = -y }
        while y != 0 {
            fin temp = y
            y = x % y
            x = temp
        }
        return x
    }

    /**
     * Computes the least common multiple.
     *
     * @param a The first integer.
     * @param b The second integer.
     * @return The LCM of a and b.
     */
    @Experimental(sinceAzora: "0.0.1")
    func lcm<T>(a: T, b: T): T
    out {
        assert it >= 0 { "LCM must be non-negative" }
    } zone {
        if a == 0 || b == 0 { return 0 }
        var absA = a
        if absA < 0 { absA = -absA }
        var absB = b
        if absB < 0 { absB = -absB }
        return absA / gcd<T>(a, b) * absB
    }

