     * Computes the sum of an integer array.
     *
     * @param arr The array to sum.
     * @return The sum of all elements.
     */
    @Experimental(sinceAzora: "0.0.1")
    func sum<T>(arr: Array<T>): T {
        var total = 0
        for i in 0..<arr.length {
            total += arr[i]
        }
        return total
    }

    /**
     * Computes the sum of a real array.
     *
     * @param arr The array to sum.
     * @return The sum of all elements.
     */
    @Experimental(sinceAzora: "0.0.1")
    func sumReal<T>(arr: Array<T>): T {
        var total = 0.0
        for i in 0..<arr.length {
            total += arr[i]
        }
        return total
    }

    /**
     * Computes the product of an integer array.
     *
     * @param arr The array to multiply.
     * @return The product of all elements.
     */
    @Experimental(sinceAzora: "0.0.1")
    func product<T>(arr: Array<T>): T {
        if arr.length == 0 { return 0 }
        var result = 1
        for i in 0..<arr.length {
            result = result * arr[i]
        }
        return result
    }

    /**
     * Computes the Nth Fibonacci number (fib).
     *
     * @param n The index (0-based) of the Fibonacci number.
     * @return The Nth Fibonacci number.
     */
    @Experimental(sinceAzora: "0.0.1")
    func fib<T>(n: T): T
    in {
        assert n >= 0 { "Fibonacci requires non-negative input" }
    } out {
        assert it >= 0 { "Fibonacci result must be non-negative" }
    } zone {
        if n == 0 { return 0 }
        if n == 1 { return 1 }
        var a = 0
        var b = 1
        var i = 2
        while i <= n {
            fin temp = a + b
            a = b
            b = temp
            i += 1
        }
        return b
    }

    /**
     * Checks if a number is prime.
     *
     * @param n The number to check (must be non-negative).
     * @return true if n is prime.
     */
    @Experimental(sinceAzora: "0.0.1")
    func isPrime(n: Int): Bool
    in {
        assert n >= 0 { "isPrime requires non-negative input" }
    } zone {
        if n < 2 { return false }
        if n < 4 { return true }
        if n % 2 == 0 { return false }
        if n % 3 == 0 { return false }
        var i = 5
        while i * i <= n {
            if n % i == 0 { return false }
            if n % (i + 2) == 0 { return false }
            i += 6
        }
        return true
    }

    /**
     * Computes the average of an integer sequence.
     *
     * @param arr The values to average (must be non-empty).
     * @return The average as a real number.
     */
    @Experimental(sinceAzora: "0.0.1")
    func average(arr: [Int]): Real
    in {
        assert arr.length > 0 { "Input must not be empty" }
    } zone {
        var total = 0
        for i in 0..<arr.length {
            total += arr[i]
        }
        return (total as Real) / (arr.length as Real)
    }

    /**
     * Computes n choose k (binomial coefficient).
     *
     * @param n The total count.
     * @param k The selection count.
     * @return C(n, k).
     */
    @Experimental(sinceAzora: "0.0.1")
    func choose(n: Int, k: Int): Int
    in {
        assert n >= 0 { "n must be non-negative" }
        assert k >= 0 { "k must be non-negative" }
        assert k <= n { "k must be <= n" }
    } zone {
        if k == 0 || k == n { return 1 }
        var result = 1
        var i = 0
        fin kk = if k > n - k { n - k } else { k }
        while i < kk {
            result = result * (n - i)
            result = result / (i + 1)
            i += 1
        }
        return result
    }

    /**
     * Computes the integer square root (floor of sqrt).
     *
     * @param n The non-negative integer.
     * @return The largest integer whose square is <= n.
     */
    @Experimental(sinceAzora: "0.0.1")
    func isqrt(n: Int): Int
    in {
        assert n >= 0 { "isqrt requires non-negative input" }
    } out {
        assert it * it <= n { "isqrt result squared must be <= n" }
    } zone {
        if n == 0 { return 0 }
        var x = n
        var y = (x + 1) / 2
        while y < x {
            x = y
            y = (x + n / x) / 2
        }
        return x
    }
}

