module std.memory.arc

/**
 * @file std/memory/arc
 *
 * An automatically reference-counted pointer (`Arc<T>`).
 *
 * `Arc` shares one heap allocation across multiple owners, keeping a count of live references.
 * `retain()` records a new owner; `release()` drops one and reclaims the allocation when the count
 * reaches zero. The single-threaded interpreter counts plainly; native backends may use atomics.
 *
 * @since 0.0.3
 */

friend zone std {
    /**
     * A reference-counted pointer to a `T`.
     *
     * @param T the pointee type.
     */
    @SinceAzora("0.0.3")
    pack<T> Arc {
        shield var raw: T*
        shield var count: Int
    }

    @Experimental(sinceAzora: "0.0.3")
    impl deref for Arc<T> { ref self ->
        return deref self.raw
    }

    impl Arc<T> {
        /** The pointed-to value. */
        @SinceAzora("0.0.3")
        prop get: T = deref self.raw

        /** Replaces the pointed-to value without changing ownership. */
        @Experimental(sinceAzora: "0.0.3")
        func set(value: T) { self.raw[0] = value }

        /** Records a new shared owner. Returns the new reference count. */
        @Experimental(sinceAzora: "0.0.3")
        func retain(): Int {
            self.count = self.count + 1
            return self.count
        }

        /** Drops a shared owner; reclaims the allocation when the count reaches zero. */
        @Experimental(sinceAzora: "0.0.3")
        func release(): Int {
            self.count = self.count - 1
            if self.count <= 0 {
                drop self.raw
            }
            return self.count
        }

        /** The current number of live references. */
        @SinceAzora("0.0.3")
        prop refCount: Int = self.count

        /** The underlying `T*` (escapes the counting). */
        @SinceAzora("0.0.3")
        prop ptr: T* = self.raw
    }

    @Experimental(sinceAzora: "0.0.3")
    func arcOf<T>(value: T): Arc<T> {
        return Arc(alloc value, 1)
    }
}

