module std.memory.ptr

/**
 * @file std/memory/ptr
 *
 * A thin owning raw-pointer wrapper around `T*`.
 *
 * `Ptr<T>` encapsulates a single heap allocation so the pointer can be passed around, dereferenced,
 * and freed explicitly. It is the unchecked counterpart to [Arc] — no reference counting; the
 * caller owns the lifetime.
 *
 * @since 0.0.3
 */

friend zone std {
    /**
     * An owning wrapper around a raw `T*`.
     *
     * @param T the pointee type.
     */
    @SinceAzora("0.0.3")
    pack<T> Ptr {
        confine var raw: T*
    }

    @Experimental(sinceAzora: "0.0.3")
    impl deref for Ptr<T> { ref self ->
        return deref self.raw
    }

    impl Ptr<T> {
        /** The pointed-to value. */
        @SinceAzora("0.0.3")
        prop get: T = deref self.raw

        /** Replaces the pointed-to value. */
        @Experimental(sinceAzora: "0.0.3")
        func set(value: T) { self.raw[0] = value }

        /** The underlying `T*` (escapes the wrapper). */
        @SinceAzora("0.0.3")
        prop ptr: T* = self.raw

        /** Whether this wrapper holds a non-null pointer. */
        @SinceAzora("0.0.3")
        prop isNull: Bool = self.raw == null
    }

    @Experimental(sinceAzora: "0.0.3")
    func ptrOf<T>(value: T): Ptr<T> {
        return Ptr(alloc value)
    }
}

