module std.memory.slice

/**
 * @file std/memory/slice
 *
 * Bounds-carrying view over a contiguous pointer range.
 *
 * @since 0.0.3
 */

friend zone std {
    @SinceAzora("0.0.3")
    pack<T> Slice {
        confine var raw: T*
        shield var count: Int
    }

    @Experimental(sinceAzora: "0.0.3")
    impl oper[] for Slice<T> { ref self, index ->
        assert index >= 0 && index < self.count { "Slice index out of bounds" }
        return self.raw[index]
    }

    @Experimental(sinceAzora: "0.0.3")
    impl oper[]= for Slice<T> { mut ref self, index, value ->
        assert index >= 0 && index < self.count { "Slice index out of bounds" }
        self.raw[index] = value
    }

    impl Slice<T> {
        /** `true` when the slice has no elements. */
        @SinceAzora("0.0.3")
        prop isEmpty: Bool = count == 0

        /** `true` when the slice has at least one element. */
        @SinceAzora("0.0.3")
        prop isNotEmpty: Bool = count > 0

        /** Returns the raw underlying `T*`. */
        @SinceAzora("0.0.3")
        prop ptr: T* = self.raw

        /** Returns a sub-slice `[start, start+count)`; asserts bounds. */
        @Experimental(sinceAzora: "0.0.3")
        func sub(start: Int, count: Int): Slice<T> {
            assert start >= 0 { "Slice start must be non-negative" }
            assert count >= 0 { "Slice count must be non-negative" }
            assert start + count <= self.count { "Slice range out of bounds" }
            return Slice(self.raw + start, count)
        }
    }

    /** Constructs a `Slice<T>` over [length] elements starting at [ptr]. */
    @Experimental(sinceAzora: "0.0.3")
    func sliceOf<T>(ptr: T*, length: Int): Slice<T> {
        return Slice(ptr, length)
    }

    /** Alias of [sliceOf]. */
    @Experimental(sinceAzora: "0.0.3")
    func ptrSlice<T>(ptr: T*, length: Int): Slice<T> {
        return sliceOf(ptr, length)
    }
}

