module std.memory.unique

/**
 * @file std/memory/unique
 *
 * Unique owning pointer. It models a single owner of one heap allocation.
 *
 * @since 0.0.3
 */

friend zone std {
    @SinceAzora("0.0.3")
    pack<T> Unique {
        confine var raw: T*
        shield var active: Bool = true
    }

    @Experimental(sinceAzora: "0.0.3")
    impl deref for Unique<T> { ref self ->
        assert self.active { "Unique pointer was released" }
        return deref self.raw
    }

    impl Unique<T> {
        /** Returns the owned value (panics if already released). */
        @Experimental(sinceAzora: "0.0.3")
        prop get: T {
            assert active { "Unique pointer was released" }
            return deref self.raw
        }

        /** Overwrites the owned value (panics if already released). */
        @Experimental(sinceAzora: "0.0.3")
        func set(value: T) {
            assert active { "Unique pointer was released" }
            self.raw[0] = value
        }

        /** Returns the raw `T*` without relinquishing ownership. */
        @Experimental(sinceAzora: "0.0.3")
        prop ptr: T* {
            assert active { "Unique pointer was released" }
            return self.raw
        }

        /**
         * Relinquishes ownership and returns the raw `T*`
         * (the value is no longer freed by the Unique).
         */
        @Experimental(sinceAzora: "0.0.3")
        func release(): T* {
            assert active { "Unique pointer was already released" }
            self.active = false
            return self.raw
        }

        /** Frees the owned value now (a no-op if already released/disposed). */
        @Experimental(sinceAzora: "0.0.3")
        func dispose() {
            if active {
                drop self.raw
                self.active = false
            }
        }
    }

