module std.parallelism.channel

/**
 * @file std/parallelism/channel
 *
 * Thread-safe message channel.
 *
 * Provides a FIFO message queue for communication between threads,
 * with send, receive, and close operations protected by a mutex.
 *
 * @since 0.0.1
 */

friend zone std {
    /**
     * A thread-safe FIFO message channel for inter-thread communication.
     *
     * Channel provides a synchronized queue that allows threads to
     * send and receive messages safely.
     *
     * @param T The type of messages in this channel.
     */
    @SinceAzora("0.0.1")
    pack<T> Channel {
        confine var queue: Queue<T> = Queue<T>()
        confine var mutex: Mutex = Mutex(0)
        confine var closed: Bool = false
    }

    impl Channel<T> {
        // --- Capacity ---

        /** The number of messages currently in the channel. */
        @SinceAzora("0.0.1")
        prop length: Int = queue.length

        /** Whether the channel has no messages. */
        @SinceAzora("0.0.1")
        prop isEmpty: Bool = queue.isEmpty

        /** Whether the channel has been closed. */
        @SinceAzora("0.0.1")
        prop isClosed: Bool = closed

        // --- Operations ---

        /**
         * Sends a message to the channel.
         *
         * @param value The message to send.
         * @throws AssertionError if the channel is closed.
         */
        @Experimental(sinceAzora: "0.0.1")
        func send(value: T) {
            assert !closed { "Cannot send on closed channel" }
            mutex.lock()
            queue.enqueue(value)
            mutex.unlock()
        }

        /**
         * Receives and removes the next message from the channel.
         *
         * @return The next message.
         * @throws AssertionError if the channel is empty.
         */
        @Experimental(sinceAzora: "0.0.1")
        func receive(): T {
            assert queue.isNotEmpty { "Channel is empty" }
            mutex.lock()
            fin value = queue.dequeue()
            mutex.unlock()
            return value
        }

        /**
         * Attempts to receive a message without blocking.
         *
         * @param default The value to return if the channel is empty.
         * @return The next message, or the default value if empty.
         */
        @Experimental(sinceAzora: "0.0.1")
        func tryReceive(default: T): T {
            mutex.lock()
            if queue.isEmpty {
                mutex.unlock()
                return default
            }
            fin value = queue.dequeue()
            mutex.unlock()
            return value
        }

        /**
         * Closes the channel, preventing further sends.
         */
        @SinceAzora("0.0.1")
        func close() {
            self.closed = true
        }
    }
}

