        options: ref SerializerOptions
    ): String!SerializationError {
        return try encodeSerialValueAtDepth(value, format, options, 0)
    }

    /**
     * Decodes one complete JSON or AZON document.
     *
     * The decoder rejects trailing content, malformed UTF escapes, invalid
     * number grammar, excessive nesting, oversized input, and duplicate keys by
     * default. AZON uses the same scalar and collection grammar as JSON, with
     * `=` replacing `:` for object members.
     */
    @Experimental(sinceAzora: "0.0.4")
    func decodeSerialValue(
        input: String,
        format: SerializationFormat,
        options: ref SerializerOptions
    ): SerialValue!SerializationError {
        if stringLength(input) > options.maxInputLength { fail return .InputTooLarge }
        var reader = SerialReader(input, 0, format, options)
        fin value = try reader.readValue(0)
        reader.skipWhitespace()
        if !reader.isAtEnd { fail return .TrailingContent }
        return value
    }

    /** Internal cursor used by the strict text decoder. */
    confine pack SerialReader {
        var input: String
        var index: Int
        fin format: SerializationFormat
        fin options: SerializerOptions
    }

    confine impl SerialReader {
        prop isAtEnd: Bool = self.index >= stringLength(self.input)

        func skipWhitespace(): Unit { mut ref self ->
            while !self.isAtEnd {
                fin c = charAt(self.input, self.index)
                if c != ' ' && c != '\n' && c != '\r' && c != '\t' { return }
                self.index += 1
            }
        }

        func take(): Char!SerializationError { mut ref self ->
            if self.isAtEnd { fail return .UnexpectedEnd }
            fin c = charAt(self.input, self.index)
            self.index += 1
            return c
        }

        func expect(expected: Char): Unit!SerializationError { mut ref self ->
            fin actual = try self.take()
            if actual != expected { fail return .InvalidSyntax }
        }

        func readValue(depth: Int): SerialValue!SerializationError { mut ref self ->
            if depth > self.options.maxDepth { fail return .MaxDepthExceeded }
            self.skipWhitespace()
            if self.isAtEnd { fail return .UnexpectedEnd }
            fin c = charAt(self.input, self.index)
            if c == '"' { return SerialValue.Text(try self.readString()) }
            if c == '[' { return try self.readArray(depth + 1) }
            if c == '{' { return try self.readObject(depth + 1) }
            if c == 't' {
                try self.readLiteral("true")
                return SerialValue.Bool(true)
            }
            if c == 'f' {
                try self.readLiteral("false")
                return SerialValue.Bool(false)
            }
            if c == 'n' {
                try self.readLiteral("null")
                return SerialValue.Null
            }
            if c == '-' || (c >= '0' && c <= '9') {
                return SerialValue.Number(try self.readNumber())
            }
            fail return .InvalidSyntax
        }

        func readLiteral(expected: String): Unit!SerializationError { mut ref self ->
            for i in 0..<stringLength(expected) {
                if try self.take() != charAt(expected, i) { fail return .InvalidSyntax }
            }
        }

        func readString(): String!SerializationError { mut ref self ->
            try self.expect('"')
            var result = ""
            while !self.isAtEnd {
                fin c = try self.take()
                if c == '"' { return result }
                if charToCode(c) < 32 { fail return .InvalidEscape }
                if c != '\\' {
                    result = result + std::convert::toString(c)
                } else {
                    fin escaped = try self.take()
                    if escaped == '"' { result = result + "\"" }
                    else if escaped == '\\' { result = result + "\\" }
                    else if escaped == '/' { result = result + "/" }
                    else if escaped == 'b' { result = result + "\b" }
                    else if escaped == 'f' { result = result + "\f" }
                    else if escaped == 'n' { result = result + "\n" }
                    else if escaped == 'r' { result = result + "\r" }
                    else if escaped == 't' { result = result + "\t" }
                    else if escaped == 'u' {
                        fin codePoint = try self.readEscapedCodePoint()
                        result = result + std::convert::toString(codeToChar(codePoint))
                    } else { fail return .InvalidEscape }
                }
            }
            fail return .UnexpectedEnd
        }

        func readHexUnit(): Int!SerializationError { mut ref self ->
            var value = 0
            for i in 0..<4 {
                fin c = try self.take()
                if !charIsHexDigit(c) { fail return .InvalidEscape }
                value = value * 16 + hexDigitToInt(c)
            }
            return value
        }

        func readEscapedCodePoint(): Int!SerializationError { mut ref self ->
            fin first = try self.readHexUnit()
            if first >= 56320 && first <= 57343 { fail return .InvalidEscape }
            if first < 55296 || first > 56319 { return first }

            // A high surrogate must be immediately followed by a low surrogate.
            if try self.take() != '\\' || try self.take() != 'u' { fail return .InvalidEscape }
            fin second = try self.readHexUnit()
            if second < 56320 || second > 57343 { fail return .InvalidEscape }
            return 65536 + (first - 55296) * 1024 + (second - 56320)
        }

        func readNumber(): String!SerializationError { mut ref self ->
            fin start = self.index
            if charAt(self.input, self.index) == '-' { self.index += 1 }
            if self.isAtEnd { fail return .InvalidNumber }

            if charAt(self.input, self.index) == '0' {
                self.index += 1
            } else {
                if !charIsDigit(charAt(self.input, self.index)) { fail return .InvalidNumber }
                while !self.isAtEnd && charIsDigit(charAt(self.input, self.index)) { self.index += 1 }
            }

            if !self.isAtEnd && charAt(self.input, self.index) == '.' {
                self.index += 1
                if self.isAtEnd || !charIsDigit(charAt(self.input, self.index)) { fail return .InvalidNumber }
                while !self.isAtEnd && charIsDigit(charAt(self.input, self.index)) { self.index += 1 }
            }

            if !self.isAtEnd && (charAt(self.input, self.index) == 'e' || charAt(self.input, self.index) == 'E') {
                self.index += 1
                if !self.isAtEnd && (charAt(self.input, self.index) == '+' || charAt(self.input, self.index) == '-') {
                    self.index += 1
                }
                if self.isAtEnd || !charIsDigit(charAt(self.input, self.index)) { fail return .InvalidNumber }
                while !self.isAtEnd && charIsDigit(charAt(self.input, self.index)) { self.index += 1 }
            }
            return substring(self.input, start, self.index)
        }

        func readArray(depth: Int): SerialValue!SerializationError { mut ref self ->
            try self.expect('[')
            var values = List<SerialValue>()
            self.skipWhitespace()
            if !self.isAtEnd && charAt(self.input, self.index) == ']' {
                self.index += 1
                return SerialValue.Array(values)
            }
            loop {
                values.add(try self.readValue(depth))
                self.skipWhitespace()
                fin separator = try self.take()
                if separator == ']' { return SerialValue.Array(values) }
                if separator != ',' { fail return .InvalidSyntax }
                self.skipWhitespace()
            }
        }

        func readObject(depth: Int): SerialValue!SerializationError { mut ref self ->
            try self.expect('{')
            var fields = List<SerialField>()
            self.skipWhitespace()
            if !self.isAtEnd && charAt(self.input, self.index) == '}' {
                self.index += 1
                return SerialValue.Object(fields)
            }
            loop {
                self.skipWhitespace()
                if self.isAtEnd || charAt(self.input, self.index) != '"' { fail return .InvalidSyntax }
                fin name = try self.readString()
                self.skipWhitespace()
                try self.expect(':')
                self.skipWhitespace()
                fin value = try self.readValue(depth)

                var duplicate = false
                for i in 0..<fields.size {
                    if serialFieldAt(fields, i).name == name { duplicate = true }
                }
                if duplicate && !self.options.allowDuplicateFields { fail return .DuplicateField }
                fields.add(SerialField(name, value))

                self.skipWhitespace()
                fin separator = try self.take()
                if separator == '}' { return SerialValue.Object(fields) }
                if separator != ',' { fail return .InvalidSyntax }
                self.skipWhitespace()
            }
        }
    }

    confine func encodeSerialValueAtDepth(
        value: ref SerialValue,
        format: SerializationFormat,
        options: ref SerializerOptions,
        depth: Int
    ): String!SerializationError {
        if depth > options.maxDepth { fail return .MaxDepthExceeded }
        when value {
            SerialValue.Null -> { return "null" }
            SerialValue.Bool(v) -> { return if v { "true" } else { "false" } }
            SerialValue.Number(v) -> {
                if !isValidSerialNumber(v) { fail return .InvalidNumber }
                return v
            }
            SerialValue.Text(v) -> { return quoteSerialString(v) }
            SerialValue.Array(values) -> {
                var result = "["
                for i in 0..<values.size {
                    if i > 0 { result = result + "," }
                    if options.pretty { result = result + "\n" + repeatIndent(options.indent, depth + 1) }
                    result = result + try encodeSerialValueAtDepth(values[i], format, options, depth + 1)
                }
                if options.pretty && values.size > 0 { result = result + "\n" + repeatIndent(options.indent, depth) }
                return result + "]"
            }
            SerialValue.Object(fields) -> {
                var result = "{"
                var i = 0
                var written = 0
                while i < fields.size {
                    fin field = serialFieldAt(fields, i)
                    var include = true
                    when field.value {
                        SerialValue.Null -> { include = options.encodeNulls }
                        else -> {}
                    }
                    if include {
                        if written > 0 { result = result + "," }
                        if options.pretty { result = result + "\n" + repeatIndent(options.indent, depth + 1) }
                        result = result + quoteSerialString(field.name)
                        result = result + ":"
                        if options.pretty { result = result + " " }
                        result = result + try encodeSerialValueAtDepth(field.value, format, options, depth + 1)
                        written += 1
                    }
                    i += 1
                }
                if options.pretty && written > 0 { result = result + "\n" + repeatIndent(options.indent, depth) }
                return result + "}"
            }
        }
        fail return .UnexpectedType
    }

    confine func quoteSerialString(value: String): String {
        var result = "\""
        for i in 0..<stringLength(value) {
            fin c = charAt(value, i)
            if c == '"' { result = result + "\\\"" }
            else if c == '\\' { result = result + "\\\\" }
            else if c == '\b' { result = result + "\\b" }
            else if c == '\f' { result = result + "\\f" }
            else if c == '\n' { result = result + "\\n" }
            else if c == '\r' { result = result + "\\r" }
            else if c == '\t' { result = result + "\\t" }
            else if charToCode(c) < 32 { result = result + "\\u" + hex4(charToCode(c)) }
            else { result = result + std::convert::toString(c) }
        }
        return result + "\""
    }

    confine func repeatIndent(indent: String, count: Int): String {
        var result = ""
        for i in 0..<count {
            result = result + indent
        }
        return result
    }

    confine func hex4(value: Int): String {
        fin digits = "0123456789abcdef"
        return std::convert::toString(charAt(digits, (value / 4096) % 16)) +
            std::convert::toString(charAt(digits, (value / 256) % 16)) +
            std::convert::toString(charAt(digits, (value / 16) % 16)) +
            std::convert::toString(charAt(digits, value % 16))
    }

    /** Validates the complete RFC 8259 number grammar without converting it. */
    @Experimental(sinceAzora: "0.0.4")
    func isValidSerialNumber(value: String): Bool {
        if stringLength(value) == 0 { return false }
        var i = 0
        if charAt(value, i) == '-' { i += 1 }
        if i >= stringLength(value) { return false }
        if charAt(value, i) == '0' {
            i += 1
        } else {
            if !charIsDigit(charAt(value, i)) { return false }
            while i < stringLength(value) && charIsDigit(charAt(value, i)) { i += 1 }
        }
        if i < stringLength(value) && charAt(value, i) == '.' {
            i += 1
            if i >= stringLength(value) || !charIsDigit(charAt(value, i)) { return false }
            while i < stringLength(value) && charIsDigit(charAt(value, i)) { i += 1 }
        }
        if i < stringLength(value) && (charAt(value, i) == 'e' || charAt(value, i) == 'E') {
            i += 1
            if i < stringLength(value) && (charAt(value, i) == '+' || charAt(value, i) == '-') { i += 1 }
            if i >= stringLength(value) || !charIsDigit(charAt(value, i)) { return false }
            while i < stringLength(value) && charIsDigit(charAt(value, i)) { i += 1 }
        }
        return i == stringLength(value)
    }
}

