    fin tree = serializer.toSerialValue(ManualTextValue("round-trip")) catch SerialValue.Null
    fin json = std::encodeSerialValue(tree, SerializationFormat.Json, options) catch "error"
    fin decodedTree = std::decodeSerialValue(json, SerializationFormat.Json, options) catch SerialValue.Null
    fin decoded = serializer.fromSerialValue(decodedTree) catch ManualTextValue("failed")
    assert decoded.value == "round-trip" { "custom serializers must compose with wire formats" }
}

