test "serial text extraction validates the slot type" {
    fin text = std::serialAsText(SerialValue.Text("Azora")) catch "failed"
    fin fallback = std::serialAsText(SerialValue.Bool(true)) catch "wrong-type"
    assert text == "Azora" { "serialAsText must return text payloads" }
    assert fallback == "wrong-type" { "serialAsText must reject non-text values" }
}

test "serial bool extraction validates the slot type" {
    fin boolean = std::serialAsBool(SerialValue.Bool(true)) catch false
    fin fallback = std::serialAsBool(SerialValue.Text("true")) catch false
    assert boolean { "serialAsBool must return Boolean payloads" }
    assert !fallback { "serialAsBool must reject non-Boolean values" }
}

test "serial char extraction requires exactly one character" {
    fin character = std::serialAsChar(SerialValue.Text("A")) catch '?'
    fin fallback = std::serialAsChar(SerialValue.Text("AB")) catch '?'
    assert character == 'A' { "serialAsChar must return one character" }
    assert fallback == '?' { "serialAsChar must reject wider strings" }
}

test "serial long extraction accepts signed integers" {
    fin positive = std::serialAsLong(SerialValue.Number("42")) catch -1L
    fin negative = std::serialAsLong(SerialValue.Number("-17")) catch 0L
    assert positive == 42L { "serialAsLong must parse positive integers" }
    assert negative == -17L { "serialAsLong must parse negative integers" }
}

test "serial long extraction rejects real syntax" {
    fin fraction = std::serialAsLong(SerialValue.Number("1.5")) catch -1L
    fin exponent = std::serialAsLong(SerialValue.Number("1e2")) catch -2L
    assert fraction == -1L { "integral decoding must reject fractions" }
    assert exponent == -2L { "integral decoding must reject exponents" }
}

test "serial long extraction rejects overflow" {
    fin overflow = std::serialAsLong(SerialValue.Number("9223372036854775808")) catch -1L
    assert overflow == -1L { "integral decoding must reject values above Long" }
}

test "serial long extraction accepts the minimum value" {
    fin minimum = std::serialAsLong(SerialValue.Number("-9223372036854775808")) catch 0L
    assert minimum == 0L - 9223372036854775807L - 1L {
        "serialAsLong must preserve the full signed Long range"
    }
}

test "serial integer extraction rejects narrowing overflow" {
    fin valid = std::serialAsInt(SerialValue.Number("2147483647")) catch -1
    fin overflow = std::serialAsInt(SerialValue.Number("2147483648")) catch -2
    assert valid == 2147483647 { "serialAsInt must accept Int.MAX_VALUE" }
    assert overflow == -2 { "serialAsInt must reject values above Int" }
}

test "serial real extraction accepts fractions" {
    fin value = std::serialAsReal(SerialValue.Number("12.5")) catch -1.0
    assert value == 12.5 { "serialAsReal must parse fractional numbers" }
}

test "serial real extraction accepts exponents" {
    fin positive = std::serialAsReal(SerialValue.Number("1.25e2")) catch -1.0
    fin negative = std::serialAsReal(SerialValue.Number("2.5e-1")) catch -1.0
    assert positive == 125.0 { "serialAsReal must apply positive exponents" }
    assert negative == 0.25 { "serialAsReal must apply negative exponents" }
}

test "serial number accepts zero" {
    assert std::isValidSerialNumber("0") { "zero is a valid serialized number" }
}

test "serial number accepts negative integer" {
    assert std::isValidSerialNumber("-42") { "negative integers are valid" }
}

test "serial number accepts fraction" {
    assert std::isValidSerialNumber("12.375") { "fractions are valid" }
}

test "serial number accepts exponent" {
    assert std::isValidSerialNumber("-1.25e+10") { "exponents are valid" }
}

test "serial number rejects empty input" {
    assert !std::isValidSerialNumber("") { "an empty number token is invalid" }
}

test "serial number rejects leading zero" {
    assert !std::isValidSerialNumber("01") { "leading zeroes are invalid" }
}

test "serial number rejects trailing decimal point" {
    assert !std::isValidSerialNumber("1.") { "a fraction needs digits" }
}

test "serial number rejects incomplete exponent" {
    assert !std::isValidSerialNumber("1e+") { "an exponent needs digits" }
}

test "serial number preserves exact source text" {
    fin options = std::serializerOptions()
    fin number = std::serialNumber("9007199254740993123456789") catch SerialValue.Null
    fin encoded = std::encodeSerialValue(number, SerializationFormat.Json, options) catch "error"
    assert encoded == "9007199254740993123456789" { "large integers must not lose precision" }
}

test "invalid number nodes cannot be encoded" {
    fin options = std::serializerOptions()
    fin encoded = std::encodeSerialValue(
        SerialValue.Number("01"),
        SerializationFormat.Json,
        options
    ) catch "invalid"
    assert encoded == "invalid" { "invalid number text must fail encoding" }
}

test "json encodes scalar values" {
    fin options = std::serializerOptions()
    fin nullText = std::encodeSerialValue(SerialValue.Null, SerializationFormat.Json, options) catch "error"
    fin trueText = std::encodeSerialValue(SerialValue.Bool(true), SerializationFormat.Json, options) catch "error"
    fin stringText = std::encodeSerialValue(SerialValue.Text("Azora"), SerializationFormat.Json, options) catch "error"
    assert nullText == "null" { "null encoding changed" }
    assert trueText == "true" { "boolean encoding changed" }
    assert stringText == "\"Azora\"" { "text encoding changed" }
}

test "json round trips arrays" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("[1,true,null,\"x\"]", SerializationFormat.Json, options) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "[1,true,null,\"x\"]" { "JSON arrays must round trip canonically" }
}

test "json round trips ordered objects" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("{\"id\":7,\"name\":\"Ada\"}", SerializationFormat.Json, options) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "{\"id\":7,\"name\":\"Ada\"}" { "JSON object order must be deterministic" }
}

test "azon round trips ordered objects" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("{\"id\":7,\"name\":\"Ada\"}", SerializationFormat.Azon, options) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Azon, options) catch "error"
    assert encoded == "{\"id\":7,\"name\":\"Ada\"}" { "AZON must use colon separators" }
}

test "decoder ignores insignificant whitespace" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue(" { \"a\" : [ 1, 2 ] } ", SerializationFormat.Json, options) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "{\"a\":[1,2]}" { "whitespace must not alter the value tree" }
}

test "json escapes control characters" {
    fin options = std::serializerOptions()
    fin encoded = std::encodeSerialValue(SerialValue.Text("a\nb\tc"), SerializationFormat.Json, options) catch "error"
    assert encoded == "\"a\\nb\\tc\"" { "control characters must be escaped" }
}

test "decoder resolves unicode escapes" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("\"\\u0041\"", SerializationFormat.Json, options) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"A\"" { "unicode escapes must decode to their character" }
}

test "decoder rejects invalid escapes" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("\"\\x\"", SerializationFormat.Json, options) catch SerialValue.Text("failed")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"failed\"" { "invalid escapes must fail decoding" }
}

test "decoder rejects trailing content" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("true false", SerializationFormat.Json, options) catch SerialValue.Text("failed")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"failed\"" { "trailing content must be rejected" }
}

test "decoder rejects duplicate object fields by default" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("{\"a\":1,\"a\":2}", SerializationFormat.Json, options) catch SerialValue.Text("failed")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"failed\"" { "duplicate fields must be rejected by default" }
}

test "decoder can retain duplicate object fields explicitly" {
    var options = std::serializerOptions()
    options.allowDuplicateFields = true
    fin value = std::decodeSerialValue("{\"a\":1,\"a\":2}", SerializationFormat.Json, options) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "{\"a\":1,\"a\":2}" { "explicit duplicate handling must preserve order" }
}

test "json rejects azon separators" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("{\"a\"=1}", SerializationFormat.Json, options) catch SerialValue.Text("failed")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"failed\"" { "JSON must require colon separators" }
}

test "azon rejects json separators" {
    fin options = std::serializerOptions()
    fin value = std::decodeSerialValue("{\"a\":1}", SerializationFormat.Azon, options) catch SerialValue.Text("failed")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"failed\"" { "AZON scalar value" }
}

test "decoder enforces input length" {
    var options = std::serializerOptions()
    options.maxInputLength = 4
    fin value = std::decodeSerialValue("false", SerializationFormat.Json, options) catch SerialValue.Text("failed")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"failed\"" { "maxInputLength must be enforced before parsing" }
}

test "decoder enforces nesting depth" {
    var options = std::serializerOptions()
    options.maxDepth = 0
    fin value = std::decodeSerialValue("[[]]", SerializationFormat.Json, options) catch SerialValue.Text("failed")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"failed\"" { "maxDepth must reject deeply nested input" }
}

test "encoder omits null object fields when configured" {
    var options = std::serializerOptions()
    options.encodeNulls = false
    fin value = std::decodeSerialValue("{\"a\":null,\"b\":1}", SerializationFormat.Json, std::serializerOptions()) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "{\"b\":1}" { "encodeNulls=false must omit null object fields" }
}

test "pretty encoder uses configured indentation" {
    var options = std::serializerOptions()
    options.pretty = true
    options.indent = "    "
    fin value = std::decodeSerialValue("[1,2]", SerializationFormat.Json, std::serializerOptions()) catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "[\n    1,\n    2\n]" { "pretty output must use the configured indent" }
}

test "serial field returns an existing object member" {
    fin options = std::serializerOptions()
    fin object = std::decodeSerialValue("{\"id\":17}", SerializationFormat.Json, options) catch SerialValue.Null
    fin value = std::serialField(object, "id") catch SerialValue.Null
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "17" { "serialField must return the requested value" }
}

test "serial field fails for a missing member" {
    fin options = std::serializerOptions()
    fin object = std::decodeSerialValue("{\"id\":17}", SerializationFormat.Json, options) catch SerialValue.Null
    fin value = std::serialField(object, "name") catch SerialValue.Text("missing")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"missing\"" { "serialField must fail for absent names" }
}

test "serial field rejects non-object values" {
    fin options = std::serializerOptions()
    fin value = std::serialField(SerialValue.Bool(true), "name") catch SerialValue.Text("wrong-type")
    fin encoded = std::encodeSerialValue(value, SerializationFormat.Json, options) catch "error"
    assert encoded == "\"wrong-type\"" { "serialField must reject non-object values" }
}

